INSERT INTO public.instruction_steps (id,instruction_set_id,variant_id,step_number,order_index,subtitle,description,image_url,image_original_url,image2_url,image2_original_url,video_url) VALUES
('def6043e-368f-4925-ada8-52f4f48ddf58','f23ebe36-cb08-4b2a-9f2a-52fc2ef5d45e',NULL,1,1,'Remove Grille Cover Clips','Remove clips holding the grille cover piece in place, circled in yellow. Release the clip by pushing the centre circle down, then lift the clip out.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a0e1eab5-6e9e-4a18-9b5f-2e20c2d9f1fe/step_01.jpeg',NULL,NULL,NULL,NULL),
('2ae5981f-2306-4690-b118-4154ea2cb9f7','f23ebe36-cb08-4b2a-9f2a-52fc2ef5d45e',NULL,2,2,'Remove Horns','Remove the 12mm bolts from the horns on either side. Unplug the horns and set horns & bolts aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a0e1eab5-6e9e-4a18-9b5f-2e20c2d9f1fe/step_02.jpeg',NULL,NULL,NULL,NULL),
('37dfe4c6-fc81-47c1-aaa8-d389c1dafb87','f23ebe36-cb08-4b2a-9f2a-52fc2ef5d45e',NULL,3,3,'Locate and Remove Radiator Support Bolts','Locate the three bolts pictured in the lower radiator support on the driver''s side. Remove the 10mm bolt from the position circled red & set aside. Partially remove 10mm bolts circled in yellow. Repeat on passenger''s side (mirror image).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a0e1eab5-6e9e-4a18-9b5f-2e20c2d9f1fe/step_03.jpeg',NULL,NULL,NULL,NULL),
('d08ad484-a7ec-4285-adc5-8991b1c03d0f','94d81e1f-20b0-4ce6-a68e-3aa07cdd4eaf',NULL,1,1,'Remove glove box, trim piece and side panel','Remove glove box, trim piece and side panel.
Glove box sides need to be squeezed together to allow it to rotate all the way forwards to be then unclipped from the hinge. Panels and are just held by clips.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/ec07be29-27cd-42fc-8502-1053bceea221/step_02.jpeg',NULL,NULL,NULL,NULL),
('28b5f7db-1626-4e9f-b6d6-0336e7da8a12','94d81e1f-20b0-4ce6-a68e-3aa07cdd4eaf',NULL,2,2,'Remove bolts','Remove bolts indicated.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/3396d6ec-595c-4b2d-9158-bfed6dd0ceeb.jpg',NULL,NULL,NULL,NULL),
('5d061cf5-6759-4167-a952-0e76ce2418d1','94d81e1f-20b0-4ce6-a68e-3aa07cdd4eaf',NULL,3,3,'Remove screw and pop out base plate','Pop the rear panel out partially and flex it forward to gain access to the cavity.
Pictured is the mounting location of the bracket. Bolt the UHF to the bracket prior to fitting it to the vehicle.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/ab7e6a79-10ed-4e52-b3e1-3ba4043c41fe.jpg',NULL,NULL,NULL,NULL),
('6f6205d9-dba6-4e95-8cf7-0d1de4db3389','a100eb48-a6bb-475e-98ec-bf14ccdbdb1d',NULL,1,1,'Mount Bracket','Mount the bracket in the pictured location using factory fixings.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/e0a218ce-d439-4c5e-b423-3f3a8322e8f7/step_04.jpeg',NULL,NULL,NULL,NULL),
('00a2a9c1-54b2-46ad-a3e8-7e4be76b5b59','0fe3c1f2-d1df-41dc-8b56-4d30e1acaf85',NULL,1,1,'Remove Screws and Cover','Attach the UHF to the bracket as shown here.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/0b7f1561-231d-4ba8-a10a-80538637f492/step_02.jpeg',NULL,NULL,NULL,NULL),
('54d47483-3c14-4321-a735-988e112dad70','0fe3c1f2-d1df-41dc-8b56-4d30e1acaf85',NULL,2,2,'Remove Glovebox','Twist and pull to remove the clips holding each side of the glovebox in place. Remove the glovebox entirely and set aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/ac70384b-48e5-4a67-862d-8e33b525d139.jpg',NULL,NULL,NULL,NULL),
('4d166f97-d2e1-44e4-906f-71b68fa22556','0fe3c1f2-d1df-41dc-8b56-4d30e1acaf85',NULL,3,3,'Attach UHF to Bracket','Attach the UHF and bracket assembly to the location pictured using the supplied M6 nyloc nut and washer. It may be easier to install the wiring prior to mounting the unit.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/0b7f1561-231d-4ba8-a10a-80538637f492/step_05.jpeg',NULL,NULL,NULL,NULL),
('fffe511d-8b61-4f9f-b773-54ec61923760','0fe3c1f2-d1df-41dc-8b56-4d30e1acaf85',NULL,4,4,'Mount UHF and Bracket Assembly','Remove the screws as shown. Ease the cover piece out of position to access the cavity.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/0b7f1561-231d-4ba8-a10a-80538637f492/step_06.jpeg',NULL,NULL,NULL,NULL),
('6bd01280-d0f8-4035-a715-472006b91538','d7dfa667-e586-4d63-b291-dfea9038da47',NULL,1,1,'Remove Cover Piece','Remove the cover piece from below the glove box by detaching three clips.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/1c3e11fa-e612-46fb-b62c-4675eb7c91d1.jpg',NULL,NULL,NULL,NULL),
('550c2b3e-028d-445e-9b25-d2e3dc854953','d7dfa667-e586-4d63-b291-dfea9038da47',NULL,2,2,'Detach Electrical Connector','Detach the electrical connector and set the cover piece aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/4bea35a6-0a0b-4772-844b-16c3ccd35b0f.jpg',NULL,NULL,NULL,NULL),
('ddbf621a-8804-4dff-bdd4-8d4cb36f4bde','d7dfa667-e586-4d63-b291-dfea9038da47',NULL,3,3,'Remove Bolt','Remove the bolt indicated in the image. Mount the UHF in this location as pictured. Wire up the UHF and replace the cover piece.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/dfeea8cb-d8ef-46df-b459-a00cd25ece32.jpg',NULL,NULL,NULL,NULL),
('8ef0bab5-3d5f-4214-b022-d59394a9fd2e','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,1,1,'Remove Cover Piece','Take out the clips holding the cover piece in place, and remove the cover piece.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_01.jpeg',NULL,NULL,NULL,NULL),
('830c08f2-4c2c-4dfb-9183-2a81cd729c0c','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,2,2,'Passenger Side Disassembly','Starting on the passenger side, remove the plastic clip and 10mm bolt circled red. Pry off the cable clip circled blue. Partially remove the 10mm bolt circled green.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_02.jpeg',NULL,NULL,NULL,NULL),
('2abbb621-fe3a-4acf-95e6-5d190019846f','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,3,3,'Driver Side Disassembly','On the drivers side, remove the plastic clip. Remove the 12mm nut, and pull the horn off the mount.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_03.jpeg',NULL,NULL,NULL,NULL),
('54f5f985-a6c7-4eb7-b99e-ce129015d1d2','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,4,4,'Install Brackets','Place the brackets in position, and feed the stud plate through the middle hole as pictured. Complete for both drivers and passengers side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_04.jpeg',NULL,NULL,NULL,NULL),
('7c2992ca-4dfe-4d35-9960-f7c58bf5b933','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,5,5,'Reattach Horn and Secure Brackets','Place the horn back in position fasten with original nut. Attach 13mm nut & large washer to the drivers side stud plate and tighten. Do not overtighten as plastic may split.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_05.jpeg',NULL,NULL,NULL,NULL),
('c38dba92-52b9-41fd-90fc-64bbabaf0ad3','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,6,6,'Secure Passenger Side','Reattach 10mm bolt on passenger side. Re-tighten second 10mm bolt. Attach 13mm nut & large washer to the passenger side stud plate and tighten. Do not overtighten as plastic may split.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_06.jpeg',NULL,NULL,NULL,NULL),
('46bcdb0f-0ae6-4142-b14b-942b339bea84','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,7,7,'Fit Light Bar Brackets and Position Light Bar','Fit the supplied light bar brackets to the light bar. Face them either inwards or outwards depending on what method suits the width of the mounts. Ease the light into position. The front radar harness may need to be temporarily unplugged for access.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_07.jpeg',NULL,NULL,NULL,NULL),
('ccb1bc84-9a57-4df2-86e1-42af32335f7e','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,13,13,'Install Switch and Loom','Run the switch cable into the cabin and install the supplied factory switch & loom.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_13.jpeg',NULL,NULL,NULL,NULL),
('3400d808-6e9e-4af7-857b-27583c9e3531','f23ebe36-cb08-4b2a-9f2a-52fc2ef5d45e',NULL,4,4,'Install TrailBait Brackets','Slide the TrailBait brackets behind the plastic bracket as shown. Locate the removed bolt back in the hole (circled red in previous step). Hand tighten.
Note: Determine LH & RH brackets by keeping the fold on the outside of the brackets when in their installed position.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a0e1eab5-6e9e-4a18-9b5f-2e20c2d9f1fe/step_04.jpeg',NULL,NULL,NULL,NULL),
('75f2e5c7-c87d-4266-87d0-68b5b6d72e3c','f23ebe36-cb08-4b2a-9f2a-52fc2ef5d45e',NULL,5,5,'Reinstall Horns and Tighten Bolts','Replace the bolts & horns removed in step 2, bolting through the hole in the TrailBait bracket as shown. Tighten bolts from step 3.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a0e1eab5-6e9e-4a18-9b5f-2e20c2d9f1fe/step_05.jpeg',NULL,NULL,NULL,NULL),
('18be0a09-e93d-48a1-97c1-6efad046e468','f23ebe36-cb08-4b2a-9f2a-52fc2ef5d45e',NULL,6,6,'Attach and Position Light Bar','Attach the light bar side brackets to the light bar. Mock up the light bar in position and set the light angle. This may be hard to adjust later. Install the light bar in position, underneath the mounting slots on the TrailBait brackets.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a0e1eab5-6e9e-4a18-9b5f-2e20c2d9f1fe/step_06.jpeg',NULL,NULL,NULL,NULL),
('d8c594e3-c078-4433-9ea7-0a7506665488','f23ebe36-cb08-4b2a-9f2a-52fc2ef5d45e',NULL,7,7,'Install Heat Shield (if applicable)','If the vehicle has a front camera, cover the wires & plug behind the camera with the supplied heat shield wrap.
Note: We do not warrant any heat damage that may occur to the camera & wiring if the heat shield is not installed correctly.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a0e1eab5-6e9e-4a18-9b5f-2e20c2d9f1fe/step_07.jpeg',NULL,NULL,NULL,NULL),
('6f8c42f0-3bb8-451b-93bb-881dba854604','f23ebe36-cb08-4b2a-9f2a-52fc2ef5d45e',NULL,8,8,'Final Wiring and Grille Refit','Once light is wired in, check light angle and adjust until satisfied. Complete wiring. If wiring harness is provided, use separate instructions supplied. Refit grille cover piece. Reset the clips by pushing the barb underneath so the the centre circle clicks back into position. Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/e5c200ba-e9ad-46f7-9a04-852cffc98812.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/e5c200ba-e9ad-46f7-9a04-852cffc98812.png',NULL,NULL,NULL),
('18076e49-8a01-44db-859a-ad79b595e70f','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,1,1,'Remove Grille Clips','Remove clips holding the cover piece in place by pushing the centre down to release the barb.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/f3e6b262-b229-4ee3-b6c8-21818c4ab5b9.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/f3e6b262-b229-4ee3-b6c8-21818c4ab5b9.png',NULL,NULL,NULL),
('7d1e0f4d-0641-4cd8-a28d-7061ef62a361','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,2,2,'Remove Grille Bolts','Remove the bolts on both sides of the vehicle that are holding in the sides of the grille.

Remove clips holding the cover piece in place by pushing the centre down to release the barb.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_01.jpeg',NULL,NULL,NULL,NULL),
('08809006-2885-47a0-80d7-b0a090fb2f71','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,3,3,'Un-clip Side Clips','Un-clip the side clips on both sides of the vehicle.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_02.jpeg',NULL,NULL,NULL,NULL),
('f26edafa-9037-4921-a992-85f58d65d712','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,4,4,'Remove Grille','Un-clip the sides of the grille and remove it from the vehicle. If the vehicle is equipped with radar, the loom will need to be unplugged.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_03.jpeg',NULL,NULL,NULL,NULL),
('8113f0a1-3a1d-4091-a609-f69a8d33795f','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,5,5,'Remove Bumper Bolts','Remove the 11x bolts at the bottom of the bumper.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_04.jpeg',NULL,NULL,NULL,NULL),
('19dbc63e-99b7-4ecc-92db-18d2d8f20032','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,16,16,'Adjust Beam Angle and Refit Grille','Set the beam angle of the light bar (preferably at night, where you can see the best angle visually) and tighten side bolts. Refit upper grille and cover removed in Step 1. Installation complete!',NULL,NULL,NULL,NULL,NULL),
('b5140851-3a19-40e8-a59e-3150ad027693','83f31019-c98e-486c-9c6d-dcd631da3903',NULL,1,1,'Remove Cover Piece','Take out the clips holding the cover piece in place, and remove the cover piece.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/bcae846c-96f6-419a-8173-eea879eafc4b/step_01.jpeg',NULL,NULL,NULL,NULL),
('ba1729c4-5b36-4c98-9069-9791f287755f','83f31019-c98e-486c-9c6d-dcd631da3903',NULL,2,2,'Remove Passenger Side Clips and Bolts','Starting on the passenger side, remove the plastic clip and 10mm bolt circled red.
Pry off the cable clip circled blue.
Partially remove the 10mm bolt circled green.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/bcae846c-96f6-419a-8173-eea879eafc4b/step_02.jpeg',NULL,NULL,NULL,NULL),
('1580cb03-7520-4b20-9f0a-054d983db550','83f31019-c98e-486c-9c6d-dcd631da3903',NULL,3,3,'Remove Driver Side Clip and Horn','On the drivers side, remove the plastic clip.
Remove the 12mm nut, and pull the horn off the mount.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/bcae846c-96f6-419a-8173-eea879eafc4b/step_03.jpeg',NULL,NULL,NULL,NULL),
('11cbbe33-dbdd-4fd0-ae38-e0f77fe46340','83f31019-c98e-486c-9c6d-dcd631da3903',NULL,4,4,'Position Brackets and Feed Stud Plate','Place the brackets in position, and feed the stud plate through the middle hole as pictured. Complete for both drivers and passengers side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/bcae846c-96f6-419a-8173-eea879eafc4b/step_04.jpeg',NULL,NULL,NULL,NULL),
('63083be3-532d-4bdf-910f-c956f0003bd2','83f31019-c98e-486c-9c6d-dcd631da3903',NULL,5,5,'Reattach Horn and Secure Stud Plate (Driver''s Side)','Place the horn back in position fasten with original nut.
Attach 13mm nut & large washer to the drivers side stud plate and tighten. Do not overtighten as plastic may split.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/bcae846c-96f6-419a-8173-eea879eafc4b/step_05.jpeg',NULL,NULL,NULL,NULL),
('737e9e53-50c0-4ad0-9383-17628b965b9d','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,6,6,'Remove Wheel Arch Fasteners','Remove and set aside the bolt & clip from each front wheel arch.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_05.jpeg',NULL,NULL,NULL,NULL),
('de788233-2079-482b-8fc0-230f1167c7e1','1157ee30-2f89-42f8-8418-62b8238a50a4',NULL,1,1,'Remove Glove Box','Remove the glove box by pulling the base off the hinges, then lifting it out.

Remove the five indicated screws, then pull the rear panel free.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/3caf972d-c036-4ca5-8acf-60e04943b63f.jpg',NULL,NULL,NULL,NULL),
('4d9f3ef4-968b-4fa5-860a-fa5bee35ebda','1157ee30-2f89-42f8-8418-62b8238a50a4',NULL,2,2,'Remove Rear Panel','Remove the indicated bolt, found on the upper right side of the cavity and attach the UHF to the mount, then attach the assembly in place as pictured.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/50950936-2f4f-4bcd-a7e5-791d89f28861.jpg',NULL,NULL,NULL,NULL),
('3bf7899f-23cb-4c15-903b-6014ca30d053','1157ee30-2f89-42f8-8418-62b8238a50a4',NULL,3,3,'Remove Bolt','Installation is compete. Glove box can be reinstalled once UHF has been wired up.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/74760d91-4294-4696-b844-3177224f0584/step_05.jpeg',NULL,NULL,NULL,NULL),
('c70c23be-ef85-46d3-93b5-0ecc76cd02de','aaf657af-8b41-4b7b-b774-b1f5d03f4647',NULL,1,1,'Remove Cover Piece','Remove the cover piece by removing clips holding the cover piece in. Place by pushing the centre down to release the barb.
There are 13 clips, indicated here.
Remove the cover piece and set aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f27d9d9c-2ff8-4f95-a01a-a98dd900e9b6/step_01.jpeg',NULL,NULL,NULL,NULL),
('904df6f9-84a3-418b-876f-c178365f1e05','aaf657af-8b41-4b7b-b774-b1f5d03f4647',NULL,2,2,'Pry Off Sensor','Using a trim tool or flat screw driver, pry off the sensor fitted to the lower radiator support, on the passenger side. This will be reattached later.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f27d9d9c-2ff8-4f95-a01a-a98dd900e9b6/step_02.jpeg',NULL,NULL,NULL,NULL),
('840e7a5b-6724-407e-a376-24e0a5da765b','aaf657af-8b41-4b7b-b774-b1f5d03f4647',NULL,3,3,'Remove Bolt','Remove and discard the bolt on the drivers side of the lower support.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f27d9d9c-2ff8-4f95-a01a-a98dd900e9b6/step_03.jpeg',NULL,NULL,NULL,NULL),
('447f5a4f-97a4-48ea-9a99-c0a33b9692f6','aaf657af-8b41-4b7b-b774-b1f5d03f4647',NULL,4,4,'Place Driver''s Side Bracket','Place the drivers side bracket (marked RH) into the cavity. Slide it into position by placing it as pictured, and rotating clockwise.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f27d9d9c-2ff8-4f95-a01a-a98dd900e9b6/step_04.jpeg',NULL,NULL,NULL,NULL),
('361e4e76-c3ee-48ee-b29b-9ce126709ae4','aaf657af-8b41-4b7b-b774-b1f5d03f4647',NULL,5,5,'Attach Bracket with Bolts','Attach using the supplied M6 bolts & washers. Ensure the bracket detached in Step 4 has been reattached in the same position.
*NOTE. Do not fully tighten, as the bracket needs to be able to slide along the slotted holes at this point.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f27d9d9c-2ff8-4f95-a01a-a98dd900e9b6/step_05.jpeg',NULL,NULL,NULL,NULL),
('4baede4f-d7fc-4786-b711-0746cf185dd5','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,1,1,'Remove Grille Cavity Cover','Open the bonnet and remove the grille cavity cover. This has 13 clips holding it in place.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_01.jpeg',NULL,NULL,NULL,NULL),
('fd759a30-29b5-4354-8abf-04fed8c6d4f5','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,2,2,'Remove Grille Bolts','Remove and retain the two bolts attaching the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_02.jpeg',NULL,NULL,NULL,NULL),
('2f319bcd-9c85-421f-853f-1f361fc9e503','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,3,3,'Disconnect Loom and Tubing','Disconnect the camera loom & washer tubing.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_03.jpeg',NULL,NULL,NULL,NULL),
('9e65c64f-6964-47ee-9801-598f70ac9140','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,4,4,'Release Grille Section','Starting on the driver''s side, pull firmly on the grille section by the headlight. This will pop out slightly.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_04.jpeg',NULL,NULL,NULL,NULL),
('cdadfe90-3ba8-4db6-a1b9-562d5f504642','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,5,5,'Release Grille Clips','Gently pull the grille forward, and release the clips which are found behind the area circled. Repeat steps 3 & 4 on the passenger side. These clips hold very tight, so take your time with this step.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_05.jpeg',NULL,NULL,NULL,NULL),
('a4459e97-9ce9-4f14-84c2-5ec899ddf29a','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,6,6,'Remove Grille','Work along the grille and carefully pop the clips running along the base of the grille. Take care that the grille does not fall down after it has been released. Set the grille aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_06.jpeg',NULL,NULL,NULL,NULL),
('c7385d6b-e883-4901-8113-f48c62f36caf','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,7,7,'Remove Bolt and Clip','Starting on the driver''s side, remove and retain the bolt and clip pictured.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_07.jpeg',NULL,NULL,NULL,NULL),
('f10c38e0-2227-4738-aef4-228e7cb74f08','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,8,8,'Install L-Bracket','Slide the L bracket into position, so that the two holes align. Ensure the bracket sits beneath the bumper plastic as shown. Reinsert the bolt & clip.
Note: pulling the bumper forward gives more room to insert the bracket.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_08.jpeg',NULL,NULL,NULL,NULL),
('f9b343b2-1db5-4c7d-8509-ad14cd1c5494','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,9,9,'Attach Centre U Bracket','Attach the centre U bracket with the supplied M8 stud, washer and nut.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_09.jpeg',NULL,NULL,NULL,NULL),
('8cdac3ea-d367-4667-aa9a-d746d344eda8','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,10,10,'Attach Light Bars','Attach the light bars using the supplied end bolts. Don''t fully tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_10.jpeg',NULL,NULL,NULL,NULL),
('a855486e-083e-4c05-97e4-04c726be982e','7734fab0-1793-4da4-98b2-15d94bfe3866',NULL,11,11,'Final Adjustment and Reinstallation','Once light is wired in, check light angle and adjust until satisfied, before tightening bolts from Step 10. Reinstall the grille & cavity cover as removed in steps 1 - 6.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3a685e8e-8a46-4660-8112-a1a4c0170617/step_11.jpeg',NULL,NULL,NULL,NULL),
('d19712f0-8198-4abf-a108-fce5076e4d14','aaf657af-8b41-4b7b-b774-b1f5d03f4647',NULL,6,6,'Install Passenger Side Bracket','Using the same method, install the bracket marked LH in the passenger side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f27d9d9c-2ff8-4f95-a01a-a98dd900e9b6/step_06.jpeg',NULL,NULL,NULL,NULL),
('fc532984-a180-42fa-bc37-ea71f6f3d9d9','6d113e8d-1fce-4fc4-a530-41cf650cec28',NULL,1,1,'Mount Bracket','Mount the bracket in the pictured location using the factory bolt.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/e9fb91b0-3e34-43d6-b458-2076fd2b06c8/step_02.jpeg',NULL,NULL,NULL,NULL),
('1d895b25-036c-4a54-9444-0f72e9fc383e','059f2a75-7f18-4016-8021-f0696a86fb2f',NULL,1,1,'Prepare Glovebox','Mount the UHF bracket to the location shown in the photo.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4445a532-10b7-4795-a311-c4e75abf8919/step_01.jpeg',NULL,NULL,NULL,NULL),
('66385238-d857-48a5-ac75-001f01b1d8e3','059f2a75-7f18-4016-8021-f0696a86fb2f',NULL,2,2,'Mount UHF Bracket','Unclip the glovebox from the vehicle.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4445a532-10b7-4795-a311-c4e75abf8919/step_02.jpeg',NULL,NULL,NULL,NULL),
('91dce82c-b40b-4c07-be5d-083f185851d0','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,1,1,'Remove Grille Components','Take out the clips holding the cover piece in place, and remove the cover piece.
Remove the single screw from the front of the grille (marked by the arrow in the image) Pop out the two clips found behind the upper grille (marked in yellow). Remove the upper grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_01.jpeg',NULL,NULL,NULL,NULL),
('c7763112-13dd-4b4e-8c4e-84d10b69e7e1','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,2,2,'Remove Vertical Support Bolts','Remove 2 x bolts from vertical support using a 12mm socket/spanner','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_02.jpeg',NULL,NULL,NULL,NULL),
('2b521138-f78e-4a42-962d-efd4593b151b','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,3,3,'Remove Black Clip','Remove the black clip at the base of the cavity, on each side (circled in red)','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_03.jpeg',NULL,NULL,NULL,NULL),
('0a47934c-f8d1-444b-8a39-a42c398448dc','aaf657af-8b41-4b7b-b774-b1f5d03f4647',NULL,7,7,'Refit Sensor','Refit the sensor removed in Step 3. Fasten using a cable tie for extra security.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f27d9d9c-2ff8-4f95-a01a-a98dd900e9b6/step_07.jpeg',NULL,NULL,NULL,NULL),
('15a8c9e6-d59f-4d12-bff8-4fbc15983082','aaf657af-8b41-4b7b-b774-b1f5d03f4647',NULL,8,8,'Attach Light Bar','Attach the light bar using its provided fixings.
Set the light angle before tightening. We recommend connecting the wiring and testing the light angle at night.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f27d9d9c-2ff8-4f95-a01a-a98dd900e9b6/step_08.jpeg',NULL,NULL,NULL,NULL),
('93b3c5df-a0db-40f9-a0e3-b79c4dd8a855','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,7,7,'Remove Bumper','Pull outwards on each side of the bumper to release the clips.
The bumper will now come free. Set aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_06.jpeg',NULL,NULL,NULL,NULL),
('bdedbd82-27ea-44a3-a64e-4d6bbb5ec234','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,8,8,'Install Stud Plate','Reaching down into the cavity, place a stud plate behind the two outside front bar supports as pictured.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_07.jpeg',NULL,NULL,NULL,NULL),
('25b1e10b-3c8d-44ee-a13b-41020fabfca6','2faa766b-8446-45ca-b3fb-b7457b03fce7',NULL,1,1,'Remove Glove Box','Remove glove box untwisting the pins on each side and unclipping it from the hinges.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/1b139730-21c4-4020-9dfd-225b5d45ac87/step_02.jpeg',NULL,NULL,NULL,NULL),
('0cabd78f-2de3-4bab-bde6-26ef166f199a','2faa766b-8446-45ca-b3fb-b7457b03fce7',NULL,2,2,'Attach UHF to Mount','Slide the bracket into position as pictured, and tighten bolts. Replace glovebox after wiring is complete.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/1b139730-21c4-4020-9dfd-225b5d45ac87/step_05.jpeg',NULL,NULL,NULL,NULL),
('d0fb18e0-1a90-4997-989b-c5e9627eba69','2faa766b-8446-45ca-b3fb-b7457b03fce7',NULL,3,3,'Install Bracket and Replace Glove Box','Partially loosen the two bolts indicated.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/bc7c3a84-7622-48ad-9dd1-7d55d2fcdf94.jpg',NULL,NULL,NULL,NULL),
('3a6ee1ba-0b83-4ae0-a8fd-ba2f310cf5fc','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,9,9,'Install Light Bar Mounts','Place the light bar mounts down over the studs. Check that the correct bracket is used, by ensuring the vertical side of the bracket faces the centre of the vehicle. Fix the brackets in place using the supplied M8 nyloc nuts and a 13mm socket.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_08.jpeg',NULL,NULL,NULL,NULL),
('b1c0a61b-dfb2-4e5a-9eea-30e82c852f77','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,10,10,' Complete Wiring and Adjust Light','Install the light bar using the slotted holes on the top of the TrailBait brackets.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_09.jpeg',NULL,NULL,NULL,NULL),
('81b9c778-8548-4204-b2db-d331f236f31e','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,11,11,'Install Light Bar to Brackets','Install the light bar into the brackets and complete wiring. Tighten the bolts fitted in Step 4.
Switch the light on and ensure the light angle is satisfactory. Tighten light bar bolts.

Install the light bar using the slotted holes on the top of the TrailBait brackets.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_10.jpeg',NULL,NULL,NULL,NULL),
('cb5f6683-de41-4b69-8986-f0655e6f391a','1f4471e4-4c17-4358-ad2b-3d48ac14c21e',NULL,12,12,'Reinstall Bumper and Grille','Reinstall the bumper and grille.
Installation complete.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/4aaa3509-b649-426d-8562-70a3d87407bd/step_11.jpeg',NULL,NULL,NULL,NULL),
('e193ef72-c878-4823-94be-64b9d0483284','c3b12c7f-a001-45d3-9219-7e06cdd8d1e6',NULL,1,1,'Pre-attach UHF unit','Remove the glove box','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3465ad47-2d3c-420c-91dd-3bf3f2079471/step_02.png',NULL,NULL,NULL,NULL),
('dba8e822-2ac5-4e3b-881a-66934d148391','c3b12c7f-a001-45d3-9219-7e06cdd8d1e6',NULL,2,2,'Remove glove box','Pre-attach the UHF unit to the bracket as shown.',NULL,NULL,'https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/9c77b005-1288-4c36-84ea-a065e48466af.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/9c77b005-1288-4c36-84ea-a065e48466af.png',NULL),
('6a8457c3-0295-40bc-b651-6f38cae42d20','c3b12c7f-a001-45d3-9219-7e06cdd8d1e6',NULL,3,3,'Attach to factory mount','Attach to the factory mount above the glovebox cavity.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3465ad47-2d3c-420c-91dd-3bf3f2079471/step_05.jpeg',NULL,NULL,NULL,NULL),
('2ed0c17d-d9a6-426f-a7c5-eb7399214eed','00770af8-6379-4db2-93cf-4a961721907a',NULL,1,1,'Access Passenger Side','Locate the cover plate beneath the passenger glove box. Release the clips (circled yellow), disconnect the attached plug (circled red) and remove the cover.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_03.jpeg',NULL,NULL,NULL,NULL),
('17fe85f1-b718-484a-8bad-e7069716a213','00770af8-6379-4db2-93cf-4a961721907a',NULL,2,2,'Remove Tread Plate','On the passenger side, remove the tread plate by pulling upwards to release the clips.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_04.jpeg',NULL,NULL,NULL,NULL),
('fed3283b-f33d-4407-88f2-1a87a9451a18','00770af8-6379-4db2-93cf-4a961721907a',NULL,3,3,'Remove Kick Panel','Unscrew the plastic nut and remove the kick panel.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_06.png',NULL,NULL,NULL,NULL),
('e7c5ae9d-d25e-49ac-a847-62d3943f9386','00770af8-6379-4db2-93cf-4a961721907a',NULL,4,4,'Connect Harness','Locate the loose white plug in the cavity. Connect the matching connector from the supplied harness.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_07.jpeg',NULL,NULL,NULL,NULL),
('d6625779-ab58-4c24-ba2c-073f128c53b4','00770af8-6379-4db2-93cf-4a961721907a',NULL,5,5,'Attach Earth Cable','Remove the side access panel and attach the earth cable.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_09.png',NULL,NULL,NULL,NULL),
('9334f451-bf12-46e3-b091-10fae62e7583','00770af8-6379-4db2-93cf-4a961721907a',NULL,6,6,'Remove Connector','Remove larger connector circled (located near firewall grommet).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_10.png',NULL,NULL,NULL,NULL),
('9605d0ab-69b1-4856-9d8c-27ec48f24dcf','00770af8-6379-4db2-93cf-4a961721907a',NULL,7,7,'Attach Wire Tap','Attach the supplied wire tap to the GREEN wire, and reattach connector.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_12.png',NULL,NULL,NULL,NULL),
('32858333-3672-425f-8da5-c65c479d2c75','00770af8-6379-4db2-93cf-4a961721907a',NULL,8,8,'Attach Module','Attach the module using the tap in the available position as shown.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_13.png',NULL,NULL,NULL,NULL),
('b3704502-1153-4322-a3a9-79f8b0b4ebe5','00770af8-6379-4db2-93cf-4a961721907a',NULL,9,9,'Remove Driver Side Panel','Remove the two screws circled and pull down to detach panel.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_16.jpeg',NULL,NULL,NULL,NULL),
('a59b5f90-8db0-4cf5-9c6e-5ec4237f92a7','00770af8-6379-4db2-93cf-4a961721907a',NULL,10,10,'Feed Harness','From the passenger side, feed the switch portion of the harness behind centre dash and through to drivers side (There is hollow for the harness to pass through as indicated).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_17.jpeg',NULL,NULL,NULL,NULL),
('ffac9aec-f45d-4553-b858-5c62b5b4fdd5','00770af8-6379-4db2-93cf-4a961721907a',NULL,11,11,'Remove Side Trim','Locate dash board side trim and pull firmly outwards to remove.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_18.jpeg',NULL,NULL,NULL,NULL),
('cdae9f0c-d335-49c3-9cce-b01fa4a30c72','00770af8-6379-4db2-93cf-4a961721907a',NULL,12,12,'Remove Fascia Panel','Pull firmly downwards and back on the fascia panel to release clips.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_19.jpeg',NULL,NULL,NULL,NULL),
('3d567e2d-1b67-4212-a5ee-6be4be9abeec','00770af8-6379-4db2-93cf-4a961721907a',NULL,13,13,'Attach Dash Illumination Wiretap','Attach the supplied wiretap to any adjacent plugs (pin 4) for dash illumination.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_21.jpeg',NULL,NULL,NULL,NULL),
('dd2b4eb1-0d26-4efd-a06b-b30885f6da48','00770af8-6379-4db2-93cf-4a961721907a',NULL,14,14,'Install OEM Switch','Remove the blank from the desired location and plug in & fit the supplied OEM style switch.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_23.png',NULL,NULL,NULL,NULL),
('b0b008c2-c043-45e0-bdab-8f61bd9f0611','00770af8-6379-4db2-93cf-4a961721907a',NULL,15,15,'Connect High Beam Feed','The pink wire contains the high beam feed. Connect this to the main power harness for the driving lights.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_24.png',NULL,NULL,NULL,NULL),
('c278dac9-8250-4ee4-a9f2-76b053d78ecc','00770af8-6379-4db2-93cf-4a961721907a',NULL,16,16,'Test and Refit','Test the wiring to see if you have high beam feed. Secure all wiring with the cable ties. Refit dash panels in reverse order from previous steps.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8263dfaf-4e81-4321-8f12-f2fc425f7279/step_25.png',NULL,NULL,NULL,NULL),
('3cf4d7ad-8941-4442-bfbe-4a57b895cfe1','508a8313-0e76-4762-b95f-fc4205c2d9a8',NULL,1,1,'Remove Glove Box','Remove the glove box by squeezing in the tabs on each side and pulling forwards.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/759f3a34-ce96-44f6-8b41-a02d21c807ae.jpg',NULL,NULL,NULL,NULL),
('f62929c8-8664-478f-bf0f-17d9945653c0','508a8313-0e76-4762-b95f-fc4205c2d9a8',NULL,2,2,'Remove Nut','Remove the nut indicated.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/8b380e19-e52b-4a0a-9185-60871aa9766e.jpg',NULL,NULL,NULL,NULL),
('481fdace-31b9-44f1-9544-b68dcba5cb88','508a8313-0e76-4762-b95f-fc4205c2d9a8',NULL,3,3,'Pre-attach UHF to Mount','Pre-attach the UHF to the mount as pictured.',NULL,NULL,'https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/2d28ea7c-2ab0-43fa-ac21-365911992145.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/2d28ea7c-2ab0-43fa-ac21-365911992145.png',NULL),
('54f21e6c-c29c-4db3-a1ae-f4b63af8e3c3','508a8313-0e76-4762-b95f-fc4205c2d9a8',NULL,4,4,'Attach Assembly and Reinstall Glovebox','Attach the assembly to the mounting point as pictured. Reinstall the glovebox after wiring is complete.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/e6395fb6-65c8-4e3e-8196-c070af142c3a/step_06.jpeg',NULL,NULL,NULL,NULL),
('07d76827-8924-45f7-ae63-ec34b2672727','d4258fd1-1f13-4fac-974b-7d991f8b0b87',NULL,1,1,'Remove Glove Box','Remove the glove box by pulling the base off the hinges, then lifting it out.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/84eaf40d-2238-4a45-b0e6-f2764968beb2.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/84eaf40d-2238-4a45-b0e6-f2764968beb2.png',NULL,NULL,NULL),
('010d0c27-d0e7-4004-a728-931a78354947','d4258fd1-1f13-4fac-974b-7d991f8b0b87',NULL,2,2,'Remove Nuts','Remove the two nuts indicated (1) (2).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/cfc300d4-dc84-4d3f-9fea-dd1747cd7807.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/cfc300d4-dc84-4d3f-9fea-dd1747cd7807.png',NULL,NULL,NULL),
('e124e836-e283-49b4-aa4c-5f3ccb2fab88','d4258fd1-1f13-4fac-974b-7d991f8b0b87',NULL,3,3,'Attach UHF to Mount','Attach the UHF to the mount as pictured.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/f9478b06-e948-42d1-82ac-009145107ef1.jpg',NULL,NULL,NULL,NULL),
('3a082556-4092-492a-aeaf-6d5b2d4481d9','d4258fd1-1f13-4fac-974b-7d991f8b0b87',NULL,4,4,'Attach Mount','Attach the mount as shown (UHF not pictured for demonstration purposes). The glove box can be reinstalled once the UHF has been wired up.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/72f3d705-53db-4852-bbb3-5ec3254ab9a6.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/72f3d705-53db-4852-bbb3-5ec3254ab9a6.png',NULL,NULL,NULL),
('875f2072-cd97-4400-8601-bd7d50196ead','8991fe91-ee52-4b8f-9048-cce6ebd76d07',NULL,1,1,'Remove cover clips','Remove clips holding the cover piece in place by pushing the centre down to release the barb.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f82ceef7-d98b-4d66-85aa-5813a5f8182d/step_01.jpeg',NULL,NULL,NULL,NULL),
('cae348f1-9e72-48f9-8115-f039eb06cfa1','8991fe91-ee52-4b8f-9048-cce6ebd76d07',NULL,2,2,'Place stud plate','Reaching down into the cavity*, place a stud plate behind the two outside front bar supports as pictured.
*note: front bumper needs to be removed for access on pre-2020 models.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f82ceef7-d98b-4d66-85aa-5813a5f8182d/step_02.jpeg',NULL,NULL,NULL,NULL),
('00eb12c4-16bd-420d-876d-217ae3725cf9','970e6615-6098-407a-9bfe-303a9040cad2',NULL,1,1,'Remove Bonnet Latch','Remove the three bolts holding the bonnet latch in place.
Lift the latch from its position and sit it back out of the way.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a262198b-038e-403b-8f7e-99a770e4d5e0/step_01.jpeg',NULL,NULL,NULL,NULL),
('56531cd1-8ebc-4f87-8ed6-f6a96cfe8b96','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,1,1,'Remove clips','Remove clips holding the cover piece in. Place by pushing the centre down to release the barb.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_01.jpeg',NULL,NULL,NULL,NULL),
('ee0f2678-5881-4302-87e8-38571107d584','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,4,4,'Fit Light Brackets','Fit light brackets* to each TrailBait mount as shown. Hand tighten bolts.
*Light brackets differ depending on light bar bracket pictured is for 23.3" option.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_04.jpeg',NULL,NULL,NULL,NULL),
('44ba7623-2ab0-418c-9397-196a1c3d6fa3','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,5,5,'Install Assemblies','Install the assemblies into position (shown in the image) Line up the holes in the bracket with the holes in the horizontal support. Note: the TrailBait bracket sits between the vertical support and the horizontal support (see image in step 7)','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_05.jpeg',NULL,NULL,NULL,NULL),
('8e77a9b3-fa11-493c-8b19-e1be6caeaf55','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,6,6,'Attach T-Bolt and Nyloc Nut','Push the T-Bolt through from behind, at each end hole.
Attach supplied 13mm nyloc nut & large washer to the T-Bolt. Partially tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_06.jpeg',NULL,NULL,NULL,NULL),
('60131db8-012a-4db9-8f70-60034f2c6539','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,7,7,'Refit and Tighten Bolts','Refit bolts removed in step 2, ensuring they feed through the holes in the TrailBait bracket.
Fully tighten nuts fitted in Step 6 before tightening the centre bolts.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_07.jpeg',NULL,NULL,NULL,NULL),
('52046d1a-7f81-42f4-aed4-b8dee0e81e24','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,8,8,'Position Light Bar','Ease the light into position. Take care with the bigger light bars, as these are a tight fit.
Don''t fully tighten the bolts, as you need to adjust the angle of the light in later steps.
Tighten bolts fitted in Step 4. using two 17mm spanners','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_08.jpeg',NULL,NULL,NULL,NULL),
('c99878de-6755-46c6-9a6c-05fec07fee9a','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,9,9,'Attach Piggyback Wiring Loom','Attach the piggyback wiring loom by unplugging the grey plug behind the headlight, and reattaching each end to the loom.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_09.jpeg',NULL,NULL,NULL,NULL),
('636d0651-4f19-4c86-b392-ef507fd87cfb','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,10,10,'Connect Light to Wiring Harness','Thread lead from the light into the engine bay.
Attach the light plug and piggyback connector to the main wiring harness','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_10.jpeg',NULL,NULL,NULL,NULL),
('dd71be1d-3b54-420f-ba26-90715ce3bb57','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,11,11,'Connect to Battery and Secure Wiring','Attach main harness to the battery terminals.
Bundle the excess wire in the recess behind the headlight and secure with a cable tie','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_11.jpeg',NULL,NULL,NULL,NULL),
('548f31af-7ea2-4fc0-9bfb-237d4f90e6a9','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,12,12,'Adjust Beam Angle and Refit Grille','Set the beam angle of the light bar (preferably at night, where you can see the best angle visually) and tighten side bolts.
Refit upper grille and cover removed in Step 1.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_12.jpeg',NULL,NULL,NULL,NULL),
('bb9e95e0-67f6-4931-b887-81cf17796476','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,13,13,'Detach Switch Wire (Optional)','Detach the switch wire from the main harness at the screw plug.
Make a hole in the passenger side firewall grommet and thread the harness end of the switch wire through and pull into the cabin.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_13.jpeg',NULL,NULL,NULL,NULL),
('33fe3bba-020a-4544-b040-c2b1dd3ba59f','60f25e63-d848-43ff-809b-3eb95e79e721',NULL,14,14,'Run Switch Wire and Install Switch (Optional)','Run the switch wire across the base of the dashboard to the drivers side.
Remove a switch blank and install the supplied switch.

Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/42080dfe-5dbf-4a4c-a24b-a4f196518223/step_14.jpeg',NULL,NULL,NULL,NULL),
('2b43cead-d08c-4b4d-861f-f0f30f7e2216','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,2,2,'Remove cover piece','There are 13 clips, indicated here. Remove the cover piece and set aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_02.jpeg',NULL,NULL,NULL,NULL),
('f6280acd-9c16-4ae2-b597-41bf2362513e','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,3,3,'Pry off sensor','Using a trim tool or flat screw driver, pry off the sensor fitted to the lower radiator support, on the passenger side. This will be reattached later.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_03.jpeg',NULL,NULL,NULL,NULL),
('97de616f-1ae2-4611-86d8-a7a48d122ebb','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,4,4,'Remove bolt','Remove and discard the bolt on the drivers side of the lower support.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_04.jpeg',NULL,NULL,NULL,NULL),
('ebec5a2f-44e8-4b3a-83e1-3ecf7ab74881','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,5,5,'Place driver''s side bracket','Place the drivers side bracket (marked RH) into the cavity. Slide it into position by placing it as pictured, and rotating clockwise.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_05.jpeg',NULL,NULL,NULL,NULL),
('ec05ff7f-0542-404a-af35-b825d005b664','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,6,6,'Attach driver''s side bracket','Attach using the supplied M6 bolts & washers. Ensure the bracket detached in Step 4 has been reattached in the same position.
*NOTE. Do not fully tighten, as the bracket needs to be able to slide along the slotted holes at this point.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_06.jpeg',NULL,NULL,NULL,NULL),
('82fb7c7f-f47f-4d99-a29d-34e68f7ccb97','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,7,7,'Install passenger side bracket','Using the same method, install the bracket marked LH in the passenger side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_07.jpeg',NULL,NULL,NULL,NULL),
('570c7cb9-3613-4d45-8cec-1c1226df4bf8','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,8,8,'Refit sensor','Refit the sensor removed in Step 3. Fasten using a cable tie for extra security.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_08.jpeg',NULL,NULL,NULL,NULL),
('ce48cce1-c39f-4da4-b841-57ac7e361982','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,9,9,'Lower light bar into position','Lower the light bar into position and attach using the supplied fixings.
*NOTE. Do not fully tighten. Light bar still needs to be adjusted later on.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_09.jpeg',NULL,NULL,NULL,NULL),
('cd9d57fd-9e1f-4c3e-97d4-dfe558f8e17b','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,10,10,'Centre and tighten light bar','Ensure the light bar is centred in the grille. Adjustments can be made by sliding the whole assembly left or right.
Once centred, tighten the bolts locking the brackets in place.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_10.jpeg',NULL,NULL,NULL,NULL),
('961cb8db-45c3-4ec7-854a-fe0ebed152ce','c600e64c-1384-4e79-9fec-ca0c21e78490',NULL,1,1,'Remove Grille Cavity Cover','Open the bonnet and remove the grille cavity cover. This has 13 clips holding it in place, and which can be released by unwinding the centre pin with a screwdriver and prying out the base.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b899f7f0-f0d7-43af-806a-d0345e3e5464/step_01.jpeg',NULL,NULL,NULL,NULL),
('4d7a188f-72f7-43b2-b7ca-c5d221dbb49e','c600e64c-1384-4e79-9fec-ca0c21e78490',NULL,2,2,'Remove Grille Bolts','Remove and retain the two bolts attaching the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b899f7f0-f0d7-43af-806a-d0345e3e5464/step_02.jpeg',NULL,NULL,NULL,NULL),
('65c565f8-d948-4a00-be64-6553dfd2d8bc','c600e64c-1384-4e79-9fec-ca0c21e78490',NULL,3,3,'Release Grille Section (Driver''s Side)','Starting on the driver''s side, pull firmly on the grille section by the headlight. This will pop out slightly.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b899f7f0-f0d7-43af-806a-d0345e3e5464/step_03.jpeg',NULL,NULL,NULL,NULL),
('26569528-36c7-4786-a63b-93e2eb5c87c7','c600e64c-1384-4e79-9fec-ca0c21e78490',NULL,4,4,'Release Grille Clip','Gently pull the grille forward, and release the clip which is found behind the area circled. Repeat steps 3 & 4 on the passenger side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b899f7f0-f0d7-43af-806a-d0345e3e5464/step_04.jpeg',NULL,NULL,NULL,NULL),
('564f93be-27b5-47bf-a1b6-36fb863e819f','c600e64c-1384-4e79-9fec-ca0c21e78490',NULL,5,5,'Remove Grille','Work along the grille and carefully pop the clips running along the base of the grille. Take care that the grille does not fall down after it has been released. Set the grille aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b899f7f0-f0d7-43af-806a-d0345e3e5464/step_05.jpeg',NULL,NULL,NULL,NULL),
('b6d61025-961d-4bd7-8f44-bd8a3a53b2e9','c600e64c-1384-4e79-9fec-ca0c21e78490',NULL,6,6,'Remove Bolt and Clip','Starting on the driver''s side, remove and retain the bolt and clip pictured.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b899f7f0-f0d7-43af-806a-d0345e3e5464/step_06.jpeg',NULL,NULL,NULL,NULL),
('583a38da-4c0f-4615-a17c-2dd6d888c919','c600e64c-1384-4e79-9fec-ca0c21e78490',NULL,7,7,'Install L Bracket','Slide the L bracket into position, so that the two holes align. Reinsert the bolt & clip.
Note: pulling the bumper forward gives more room to insert the bracket.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b899f7f0-f0d7-43af-806a-d0345e3e5464/step_07.jpeg',NULL,NULL,NULL,NULL),
('cdd85d66-99c5-4908-9c34-85151346020e','c600e64c-1384-4e79-9fec-ca0c21e78490',NULL,8,8,'Attach Centre U Bracket (Optional)','Skip this step if you have a 26" kit.
Attach the centre U bracket with the supplied M8 stud plate, washers and nut.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b899f7f0-f0d7-43af-806a-d0345e3e5464/step_08.jpeg',NULL,NULL,NULL,NULL),
('6d95c027-b546-4357-ba30-0cacb0f07734','8991fe91-ee52-4b8f-9048-cce6ebd76d07',NULL,3,3,'Fix light bar mounts','Place the light bar mounts down over the studs. Check that the correct bracket is used, by ensuring the vertical side of the bracket faces the centre of the vehicle. Fix the brackets in place using the supplied M8 nyloc nuts and a 13mm socket.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/f82ceef7-d98b-4d66-85aa-5813a5f8182d/step_03.jpeg',NULL,NULL,NULL,NULL),
('ade37eef-b1ef-40c9-972b-f90181c39d23','8991fe91-ee52-4b8f-9048-cce6ebd76d07',NULL,4,4,'Install light bar','Install the light bar using the slotted holes on the top of the TrailBait brackets.
For Rogue models, bolt the taller side brackets on top of the TrailBait brackets to position the light bar in the right position. Two slots will need to be cut in the trim.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/d3caecc4-c3ca-421a-b322-295ebd350a60.jpg',NULL,NULL,NULL,NULL),
('d4610c86-7e02-4a4c-8857-c2d6f7adc55f','8991fe91-ee52-4b8f-9048-cce6ebd76d07',NULL,5,5,'Complete wiring and adjust','Install the light bar into the brackets and complete wiring. Tighten the bolts fitted in Step 4.
Switch the light on and ensure the light angle is satisfactory. Tighten light bar bolts.',NULL,NULL,NULL,NULL,NULL),
('38fb7736-0137-47c3-9485-9ee54067aa48','970e6615-6098-407a-9bfe-303a9040cad2',NULL,2,2,'Remove Plastic Shroud','Remove the three clips from the plastic shroud using a flat blade screw driver to lift up the centre pin.
Remove the shroud.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a262198b-038e-403b-8f7e-99a770e4d5e0/step_02.jpeg',NULL,NULL,NULL,NULL),
('028cee7e-d291-472f-872b-6bdafede6049','970e6615-6098-407a-9bfe-303a9040cad2',NULL,3,3,'Reveal Holes','Looking down into the cavity, pry the harness clips from the metal support to reveal the holes.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a262198b-038e-403b-8f7e-99a770e4d5e0/step_03.jpeg',NULL,NULL,NULL,NULL),
('589120c2-2eef-43fc-b651-c5784956df10','970e6615-6098-407a-9bfe-303a9040cad2',NULL,4,4,'Install Brackets','Place the brackets in position. The longer bracket is for the passenger side. Note the orientation of the brackets in the image.
Bolt the brackets in position using the supplied fasteners.
Cable tie the factory wiring harness to these brackets, utilising the available vertical slots.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a262198b-038e-403b-8f7e-99a770e4d5e0/step_04.jpeg',NULL,NULL,NULL,NULL),
('79512e28-5fd4-4e45-b4a6-c4665ec3a2dd','970e6615-6098-407a-9bfe-303a9040cad2',NULL,5,5,'Assemble Light Bar','Assemble the light bar''s own brackets, then lower it into position so the holes in the base of the brackets line up with the slots in the top of the mounts installed earlier.
Centre the light bar within the grille before attached using the supplied fixings.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a262198b-038e-403b-8f7e-99a770e4d5e0/step_05.jpeg',NULL,NULL,NULL,NULL),
('3ddf40b9-0cd4-4a5d-8af0-6c903a0f8362','970e6615-6098-407a-9bfe-303a9040cad2',NULL,6,6,'Final Adjustment and Reinstallation','Ensure you are happy with the angle of the light bar before tightening bolts and reinstalling components from earlier steps.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a262198b-038e-403b-8f7e-99a770e4d5e0/step_06.jpeg',NULL,NULL,NULL,NULL),
('a7a06ded-473e-49fb-b5e2-79348b8d3ba2','c600e64c-1384-4e79-9fec-ca0c21e78490',NULL,9,9,'Attach Light Bar','Attach the light bar using the supplied end bolts. Don''t fully tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b899f7f0-f0d7-43af-806a-d0345e3e5464/step_09.jpeg',NULL,NULL,NULL,NULL),
('b25b13af-cb0e-4af7-a9ac-ff1df76e3f57','c600e64c-1384-4e79-9fec-ca0c21e78490',NULL,10,10,'Final Adjustments and Reinstallation','Once light is wired in, check light angle and adjust until satisfied, before tightening bolts from Step 9. Reinstall the grille & cavity cover as removed in steps 1 - 5.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b899f7f0-f0d7-43af-806a-d0345e3e5464/step_10.jpeg',NULL,NULL,NULL,NULL),
('5f2d819c-2164-4b00-9fe2-69901b307f67','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,11,11,'Install wiring loom','Install the wiring loom by attaching the piggyback wiring to the high-beam, and plugging in all the connectors.
Separate instructions have been provided for more detailed installation.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_11.jpeg',NULL,NULL,NULL,NULL),
('e1b5359d-521a-48dd-a303-2de3bcc1cc8f','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,12,12,'Connect wiring loom to battery','Install wiring loom to the battery terminals and feed the power wire through to the light bar. Fix in place using cable ties.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_12.jpeg',NULL,NULL,NULL,NULL),
('23bcfe36-0647-4732-a534-9ba18d3c2938','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,1,1,'Remove Cover Piece Clips','Remove clips holding the cover piece in place, circled in red. Ensure to remove the clip located underneath the air intake.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_01.jpeg',NULL,NULL,NULL,NULL),
('a5056c80-9804-4bc5-9974-c04df19d9b2f','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,2,2,'Disconnect Bonnet Rubber','Disconnect the bonnet rubber from each side of the nose piece. (Just the first 10cm on each side, not the entire rubber).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_02.jpeg',NULL,NULL,NULL,NULL),
('6a0c3fe1-c9cf-4034-8a8e-ed59642bb3af','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,3,3,'Remove Nose Piece','Have patience with the next two steps, as this part can be tough!
Starting on the driver''s side, hold the nose piece from the edge and pull directly forwards (with force) until you feel movement in the nose piece.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_03.jpeg',NULL,NULL,NULL,NULL),
('0f7e7e7b-7b25-49c3-a204-c2c5d3cda723','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,4,4,'Release Nose Piece Clips','Check underneath to see if clips become exposed. Once revealed, these can be levered with a screw driver to help release them. Continue pulling the nose piece by hand and wiggling the clips. Move from left to right until the whole piece comes free.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_04.jpeg',NULL,NULL,NULL,NULL),
('7cdb8554-94ea-47a9-9cbb-466b4c56cc1f','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,5,5,'Remove Black Cover Piece Screws','Remove the four screws holding the black cover piece in place.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_05.jpeg',NULL,NULL,NULL,NULL),
('7232220d-f1ef-460d-a4ac-f54e2ee76ffb','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,6,6,'Pry Open Cover Piece Clips','Use a flat screw driver to pry the clips open. Work from left to right to free the whole piece. Sit the cover piece aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_06.jpeg',NULL,NULL,NULL,NULL),
('918094b4-b3db-443f-87e3-729c7b752b25','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,7,7,'Remove Black Clip','Remove the black clip at the base of the cavity, on the driver''s side (circled in red).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_07.jpeg',NULL,NULL,NULL,NULL),
('92825052-15c2-4efe-81bf-0f9f7b04f0a0','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,8,8,'Remove Horn Bolt','Remove the 10mm bolt holding the driver side horn. Sit the horn aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_08.jpeg',NULL,NULL,NULL,NULL),
('1a11214c-de1f-4f75-a9b7-6615d3ff69c4','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,9,9,'Place Bracket and Reattach Horn','Place the bracket marked ''RH'' as pictured.
Reattach the horn in the original position, ensuring it mounts into the holes in the bracket. Place a washer on the bolt, between the horn and the bracket to space the horn forwards (indicated by arrow). Hand tighten only.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_09.jpeg',NULL,NULL,NULL,NULL),
('e49deae4-d637-4d20-ade7-a64f3ca7e4e1','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,10,10,'Attach T-Bolt and Nyloc Nut','Push the supplied T-Bolt through the back of the lower horizontal support where the clip was, and feed it through the hole in the bracket.
Attach a 13mm nyloc nut & washer, hand tighten only.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_10.jpeg',NULL,NULL,NULL,NULL),
('0e88ca30-d231-460f-bd3c-d96ad0f7a21b','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,11,11,'Tighten Bolts and Repeat for Passenger Side','With a 10mm spanner, tighten the top bolt.
Using a 13mm spanner, tighten the bottom nut.
Repeat steps 7 - 10 on the passenger side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_11.jpeg',NULL,NULL,NULL,NULL),
('2c869bfd-5d0d-4f5a-aa53-121ce6c4c324','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,12,12,'Attach Light Bar and Set Angle','Attach the light bar using its provided fixings. Use the upper bolt hole in the bracket.
Set the light angle before tightening. We recommend connecting the wiring and testing the light angle at night before completing the rest of the installation.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_12.jpeg',NULL,NULL,NULL,NULL),
('56eb594a-f8f9-4ee9-98f0-8e0f81ab2b9e','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,13,13,'Replace Cover and Nose Piece','Replace the black cover & nose piece removed in steps 1 - 6. Ensure clips are located correctly and snap into place.
Ensure the rubbers removed in step 2 are reattached.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_13.jpeg',NULL,NULL,NULL,NULL),
('41f8a1e4-73a2-427a-b15c-79a88efd6eaa','8279011d-40ee-4aa9-829d-47b5f5f2b964',NULL,14,14,'Installation Complete','Installation is complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/5d724707-0434-4e47-8803-1f59f1544e1b/step_14.jpeg',NULL,NULL,NULL,NULL),
('a3b5ab30-9e5f-4375-b44e-295ae5303775','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,1,1,'Remove Cover Piece','Remove clips holding the cover piece in place, including the clip hidden under the air intake (circled in green).
Set the cover piece aside & retain the clips.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_01.jpeg',NULL,NULL,NULL,NULL),
('7ad3333b-c6da-44a6-9787-773c5842ad8a','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,2,2,'Remove Clips and Bolts','At the base of the cavity, remove the black clips and the vertical support bolts (circled in red).
Perform for both driver and passenger side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_02.jpeg',NULL,NULL,NULL,NULL),
('e31b334a-de93-4d8d-86ce-1113ed51353a','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,3,3,'Assemble and Position Brackets','Assemble light bar brackets to the TrailBait brackets. Then position the assembly in the vehicle. Line up the holes in the bracket with the vehicle holes. Ensure the outer bracket tab slides behind the plastic and the inner tab slides behind the vertical support.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_03.jpeg',NULL,NULL,NULL,NULL),
('bcb60c48-ce52-4dd2-a2a9-b7595f40b67c','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,4,4,'Attach T-Bolt and Nut','Push the T-Bolt through from behind, at each end hole.
Attach supplied 13mm nyloc nut & large washer to the T-Bolt. Partially tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_04.jpeg',NULL,NULL,NULL,NULL),
('d2c04e99-6d57-4c32-a318-7c099220ec02','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,5,5,'Refit Bolts and Tighten Nuts','Refit bolts removed in step 2, ensuring they feed through the holes in the TrailBait bracket.
Fully tighten nuts fitted in step 4.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_05.jpeg',NULL,NULL,NULL,NULL),
('02201ed4-6b4b-49f4-bc53-cab0e6a5274f','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,6,6,'Position Light Bar and Attach Allen Bolts','Ease the light into position. Some light bars may need the bumper removed to gain access. Attach allen bolts into the side of the light bar (don''t fully tighten)
Tighten bolts fitted in Step 3.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_06.jpeg',NULL,NULL,NULL,NULL),
('98641dde-5a11-4dc7-9c4e-e046faa2de32','64355669-6541-4aef-95a3-d753e0a8a631',NULL,1,1,'Remove Grille Cover Clips','Remove clips holding the grille cover piece in place.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_01.jpeg',NULL,NULL,NULL,NULL),
('dc6745f8-7c55-450e-8941-84e058331a9d','64355669-6541-4aef-95a3-d753e0a8a631',NULL,2,2,'Locate Mounting Holes','Starting on the driver''s side, locate the two holes in the base plate behind the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_02.jpeg',NULL,NULL,NULL,NULL),
('8a391e58-4a2c-4ef9-b5c7-7916baea3a4e','64355669-6541-4aef-95a3-d753e0a8a631',NULL,3,3,'Position Bracket','Place the bracket indicated above both holes, lining them up with the slots.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_03.jpeg',NULL,NULL,NULL,NULL),
('ec2741f5-b0a1-4ebe-8d58-8bf8ddbde312','94fbd355-a06e-42ff-b38d-39eb2463ed45',NULL,1,1,'Remove Grille Cover Clips','Remove clips holding the grille cover piece in place.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/6c4640ab-cb76-41f9-a1c3-70932adad1e6/step_01.jpeg',NULL,NULL,NULL,NULL),
('74cd1ad2-e7c0-4840-ada0-2b728d4084cd','94fbd355-a06e-42ff-b38d-39eb2463ed45',NULL,2,2,'Locate Holes on Driver''s Side','Starting on the driver''s side, locate the two holes in the base plate behind the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/6c4640ab-cb76-41f9-a1c3-70932adad1e6/step_02.jpeg',NULL,NULL,NULL,NULL),
('f3a4fe45-6324-4c7a-8cd5-d7533dc510fd','94fbd355-a06e-42ff-b38d-39eb2463ed45',NULL,3,3,'Place Bracket','Place the bracket indicated above both holes, lining them up with the slots.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/6c4640ab-cb76-41f9-a1c3-70932adad1e6/step_03.jpeg',NULL,NULL,NULL,NULL),
('4796f9ab-0c39-43fe-957d-869a3ca32765','94fbd355-a06e-42ff-b38d-39eb2463ed45',NULL,4,4,'Insert Stud Plates and Secure Bracket','Take the supplied stud plates and insert them from underneath the holes, so that the thread rises through the slot on each side of the bracket. Attach supplied washer and nylon locking nut. Ensure bracket is sitting on an even surface before tightening.
Repeat step 2 - 4 on passenger side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/6c4640ab-cb76-41f9-a1c3-70932adad1e6/step_04.jpeg',NULL,NULL,NULL,NULL),
('312b9b86-08ec-437b-8bf3-7e914454e479','94fbd355-a06e-42ff-b38d-39eb2463ed45',NULL,5,5,'Unplug Radar Module Loom','Unplug the radar module loom from the back of the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/6c4640ab-cb76-41f9-a1c3-70932adad1e6/step_05.jpeg',NULL,NULL,NULL,NULL),
('8ba5e06f-58af-423d-a374-99df4943dee1','94fbd355-a06e-42ff-b38d-39eb2463ed45',NULL,6,6,'Attach Light Bar Side Brackets','Attach the light bar side brackets to the light bar.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/6c4640ab-cb76-41f9-a1c3-70932adad1e6/step_06.jpeg',NULL,NULL,NULL,NULL),
('76d1fa9f-592b-4558-baa7-11d2d7cb09eb','94fbd355-a06e-42ff-b38d-39eb2463ed45',NULL,7,7,'Position Light Bar','Ease light bar into position, and bolt in place through the bracket slots. Don''t fully tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/6c4640ab-cb76-41f9-a1c3-70932adad1e6/step_07.jpeg',NULL,NULL,NULL,NULL),
('19a693d2-c2ee-4dd6-a35c-af865e236248','94fbd355-a06e-42ff-b38d-39eb2463ed45',NULL,8,8,'Reattach Radar Plug','Reattach the radar plug. The bracket holding the receiver may need to be flexed upwards to clear the light bar.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/6c4640ab-cb76-41f9-a1c3-70932adad1e6/step_08.jpeg',NULL,NULL,NULL,NULL),
('1a1829ae-62f5-4276-98e3-9ffc499e1afd','94fbd355-a06e-42ff-b38d-39eb2463ed45',NULL,9,9,'Attach and Centre Light Bar','Attach and centre the light bar with the grille using its provided fixings and complete wiring.
Set the light angle before tightening. We recommend connecting the wiring and testing the light angle at night.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/6c4640ab-cb76-41f9-a1c3-70932adad1e6/step_09.jpeg',NULL,NULL,NULL,NULL),
('ad832584-846e-4eaa-a4d1-83860732621d','94fbd355-a06e-42ff-b38d-39eb2463ed45',NULL,10,10,'Reattach Cavity Cover','Reattach the cavity cover & clips from Step 1.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/6c4640ab-cb76-41f9-a1c3-70932adad1e6/step_10.jpeg',NULL,NULL,NULL,NULL),
('90993cf4-7fc1-49b4-8c8e-668cc4a57d80','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,7,7,'Locate and Unplug Headlight Plug','Locate & unplug the headlight plug (passenger side).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_07.jpeg',NULL,NULL,NULL,NULL),
('7ec6c321-44ba-49fc-82ed-9911d0501d65','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,8,8,'Attach Piggyback Connector','Take the supplied piggyback connector and attach to either end of the plug from step 7.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_08.jpeg',NULL,NULL,NULL,NULL),
('96a9d2b9-a245-42c7-aa81-62db6c5d3c37','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,9,9,'Connect Light Bar Harness','Take the light bar harness and plug it into the light bar. Plug the white connector into the piggy-back harness as pictured.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_09.jpeg',NULL,NULL,NULL,NULL),
('e635ef99-24a8-4a81-b2e1-676e093ec7f6','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,10,10,'Attach Red Harness Wire to Battery','Attach the red harness wire to the positive battery terminal as shown.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_10.jpeg',NULL,NULL,NULL,NULL),
('8dae4169-3939-4ee0-ab98-9bef846bb89c','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,11,11,'Locate Grounding Point and Attach Black Wires','Locate the grounding point in the engine bay (pictured).
Attach the black harness wire AND the black wire from the piggyback and reattach the bolt.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_11.jpeg',NULL,NULL,NULL,NULL),
('f6725882-99e1-4b9b-b712-460a47934b8f','64355669-6541-4aef-95a3-d753e0a8a631',NULL,4,4,'Install Stud Plates and Secure Bracket','Take the supplied stud plates and insert them from underneath the holes, so that the thread rises through the slot on each side of the bracket. Attached supplied washer and nylon locking nut. Ensure bracket is sitting on an even surface before tightening.
Repeat step 2 - 4 on passenger side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_04.jpeg',NULL,NULL,NULL,NULL),
('a7da834e-bc04-451b-be09-46593928d653','64355669-6541-4aef-95a3-d753e0a8a631',NULL,5,5,'Unplug Radar Module Loom','Unplug the radar module loom from the back of the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_05.jpeg',NULL,NULL,NULL,NULL),
('6176115b-2810-4daf-abb6-19f1e83a540f','64355669-6541-4aef-95a3-d753e0a8a631',NULL,6,6,'Attach Light Bar Side Brackets','Attach the light bar side brackets to the light bar.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_06.jpeg',NULL,NULL,NULL,NULL),
('fc9e3577-3444-4154-b072-1717e93f8ece','abd80c1b-a9d7-413e-bd14-e24b65dbc76d',NULL,1,1,'Remove Cover Clips','Remove clips holding the cover piece in place, including the clip hidden under the air intake (circled in green).
Set the cover piece aside & retain the clips.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/1022575f-8a37-4ca1-811d-41e0715a5617/step_01.jpeg',NULL,NULL,NULL,NULL),
('6e34ba58-95bf-41a8-9bb0-a7dbf0202964','abd80c1b-a9d7-413e-bd14-e24b65dbc76d',NULL,2,2,'Remove Clips and Bolts','At the base of the cavity, remove the black clips and the vertical support bolts (circled in red).
Perform for both driver and passenger side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/1022575f-8a37-4ca1-811d-41e0715a5617/step_02.jpeg',NULL,NULL,NULL,NULL),
('3c665016-2b5a-40a1-bd7f-a123642a8c3a','abd80c1b-a9d7-413e-bd14-e24b65dbc76d',NULL,3,3,'Determine Bracket Positioning','Determine appropriate bracket positioning, either upright or inverted.
Test by fitting light bar to the brackets and check grille & centre support clearance.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/1022575f-8a37-4ca1-811d-41e0715a5617/step_03.jpeg',NULL,NULL,NULL,NULL),
('8274c4a7-0726-40f1-bc91-3b2a797e22e5','abd80c1b-a9d7-413e-bd14-e24b65dbc76d',NULL,4,4,'Assemble and Position Brackets','Assemble light bar brackets to the TrailBait brackets. Then position the assembly in the vehicle. Line up the holes in the bracket with the vehicle holes. Ensure the outer bracket tab slides behind the plastic and the inner tab slides behind the vertical support.
Push the T-Bolt through from behind, at each end hole.
Attach supplied 13mm nyloc nut & large washer to the T-Bolt. Partially tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/1022575f-8a37-4ca1-811d-41e0715a5617/step_04.jpeg',NULL,NULL,NULL,NULL),
('98f3ff4e-9c1f-4c74-aace-3442a8555b3e','abd80c1b-a9d7-413e-bd14-e24b65dbc76d',NULL,5,5,'Refit Bolts and Tighten Nuts','Refit bolts removed in step 2, ensuring they feed through the holes in the TrailBait bracket.
Fully tighten nuts fitted in step 4.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/1022575f-8a37-4ca1-811d-41e0715a5617/step_05.jpeg',NULL,NULL,NULL,NULL),
('14dffd9b-55bb-4006-9949-84d63b7cf3a2','abd80c1b-a9d7-413e-bd14-e24b65dbc76d',NULL,6,6,'Position Light Bar and Attach Allen Bolts','Ease the light into position. Some light bars may need the bumper removed to gain access. Attach allen bolts into the side of the light bar (don''t fully tighten).
Tighten bolts fitted in Step 3.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/1022575f-8a37-4ca1-811d-41e0715a5617/step_06.jpeg',NULL,NULL,NULL,NULL),
('1c0ed9ce-4c03-422d-afec-c070706af1c9','abd80c1b-a9d7-413e-bd14-e24b65dbc76d',NULL,7,7,'Set Light Angle and Final Tightening','Set the light angle before tightening. We recommend connecting the wiring and testing the light angle at night before completing the rest of the installation.
Tighten bolts fitted in Step 6, then reattach cover and clips removed in Step 1.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/1022575f-8a37-4ca1-811d-41e0715a5617/step_07.jpeg',NULL,NULL,NULL,NULL),
('f00eb679-fe52-4f75-83ca-13dc39d7e353','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,12,12,'Bundle Excess Wire and Secure Relay','Bundle excess wire into the cavity below the headlight. Secure with supplied cable ties. Ensure the relay is well secured (It is recommended to bolt down the relay).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_12.jpeg',NULL,NULL,NULL,NULL),
('a5e482f2-8e9f-402c-9fb0-76c8b14b24cd','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,13,13,'Route Switch Wire (Optional)','Detach the switch wire from the main harness at the screw plug.
Make a hole in the passenger side firewall grommet and thread the harness end of the switch wire through and pull into the cabin.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8baa7c36-5ec9-4c55-be62-aa80c954db46/step_13.jpeg',NULL,NULL,NULL,NULL),
('fe8ca878-2687-410f-b118-b11dcd38713a','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,14,14,'Install Switch (Optional)','Run the switch wire across the base of the dashboard to the drivers side.
Remove a switch blank and install the supplied switch, wiring it to the harness.',NULL,NULL,NULL,NULL,NULL),
('cad13cdd-e858-4543-9844-5c263b296ae5','2f49dc20-df2f-4231-ada8-d4d16ec2273e',NULL,15,15,'Test Light and Final Tightening','Turn on the vehicle high beams and depress the switch. Test the light angle for best preference.
Tighten bolts fitted in Step 6, then reattach cover and clips removed in Step 1.
Installation complete!',NULL,NULL,NULL,NULL,NULL),
('5a673b26-f100-4bb1-96b7-0c5ead05deaa','64355669-6541-4aef-95a3-d753e0a8a631',NULL,7,7,'Position Light Bar','Ease light bar into position, and bolt in place through the bracket slots. Don''t fully tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_07.jpeg',NULL,NULL,NULL,NULL),
('cb283b00-361d-47f0-b86f-8a798810ffc4','64355669-6541-4aef-95a3-d753e0a8a631',NULL,8,8,'Reattach Radar Plug','Reattach the radar plug. The bracket holding the receiver may need to be flexed upwards to clear the light bar.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_08.jpeg',NULL,NULL,NULL,NULL),
('0c986f8a-d544-4b78-8817-ee6fd097aa79','64355669-6541-4aef-95a3-d753e0a8a631',NULL,9,9,'Centre and Attach Light Bar','Attach and centre the light bar with the grille using its provided fixings. Don''t fully tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_09.jpeg',NULL,NULL,NULL,NULL),
('666041d5-bb74-4ab5-b7f6-cc0944e2fba8','64355669-6541-4aef-95a3-d753e0a8a631',NULL,10,10,'Install Wiring Loom','Install the wiring loom by attaching terminals to the battery, the piggyback wiring to the high-beam, and plugging in all the connectors.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_10.jpeg',NULL,NULL,NULL,NULL),
('08f38b26-fdd6-4319-ac41-62afa088c607','64355669-6541-4aef-95a3-d753e0a8a631',NULL,11,11,'Install Switch Cable','Feed the switch cable through the firewall and attached the supplied switch. Switch will fit the centre console or driver''s panel.
Wire the switch in position using the supplied connection.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_11.jpeg',NULL,NULL,NULL,NULL),
('49cbbc5a-cd6f-452d-9893-c55f5f7fa6b8','64355669-6541-4aef-95a3-d753e0a8a631',NULL,12,12,'Final Adjustments and Reassembly','Switch the light on and ensure the light angle is satisfactory (usually easier to complete at night!).
Tighten bolts installed in Step 9.
Reattach the cavity cover & clips from Step 1.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/710d3859-36d2-4a77-b4d3-5dec768a7b4f/step_12.jpeg',NULL,NULL,NULL,NULL),
('c1149fd0-cf2c-450b-919e-a3091fdc9070','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,13,13,'Feed switch cable','Feed the switch cable through the firewall and attached the supplied switch. Switch will fit the centre console or driver''s panel.
Wire the switch in position using the supplied connection.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_13.jpeg',NULL,NULL,NULL,NULL),
('d2f330b4-0467-47fe-8a5b-bf95843e8fa6','204b71e5-b879-4f5d-a574-75ca4de6d023',NULL,14,14,'Final adjustments and reassembly','Switch the light on and ensure the light angle is satisfactory (usually easier to complete at night!).
Tighten bolts installed in Step 9, and refit the cavity cover removed in Steps 1-2. Reset the pins by pushing the barb back up.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/3cbcf699-dcbd-4585-8452-b701bcbbe082/step_14.jpeg',NULL,NULL,NULL,NULL),
('8d37a923-71d3-42ba-88a6-095c8e1f59de','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,1,1,'Step 1','Remove clips holding the cover piece in place by pushing the centre down to release the barb. Detach the cover piece and set aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_03.jpeg',NULL,NULL,NULL,NULL),
('ee5daf42-c8c3-4be6-82e0-5149f628db2f','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,2,2,'Step 2','Remove the four bolts holding the grille in place.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_07.jpeg',NULL,NULL,NULL,NULL),
('3fa5bf9d-48e6-43e6-ab41-8f9f8244fc36','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,3,3,'Step 3','Pop out the cover pieces concealing the area indicated. Remove the screws found behind these cover pieces. There is one on each side of the grille. Circled in red.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_01.jpeg',NULL,NULL,NULL,NULL),
('2b71cc8d-b2b5-470f-92bd-31b2dc755848','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,4,4,'Step 4','Reaching inside the grille cavity, remove the screw at the base of the grille, marked here.
Disconnect the plug at the back of the radar sensor (Toyota Badge). Marked by the red arrow.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_02.jpeg',NULL,NULL,NULL,NULL),
('cd58469c-380d-4955-956a-7d796c5606de','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,5,5,'Step 5','Remove the two clips from inside the grille cavity.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_14.jpeg',NULL,NULL,NULL,NULL),
('6efcbf93-f93d-4804-9f54-158546ac0004','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,6,6,'Step 6','Remove and set aside the bolt & clip from each front wheel arch.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_09.jpeg',NULL,NULL,NULL,NULL),
('cd3fba44-ff45-48e5-a780-a93314ab2c2f','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,7,7,'Step 7','On each side, remove three of the screws underneath the bumper. Partially detach bumper & grille together by pulling it away from each headlight, and dropping it forward to access the lower cavity. The areas previously attached with screws need to be pushed out of their locating holes.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_08.jpeg',NULL,NULL,NULL,NULL),
('d53bcbf0-4a7a-48a0-8c97-957dbbfc8862','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,8,8,'Step 8','Reaching down into the cavity, place a stud plate behind the two outside front bar supports as pictured.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_10.jpeg',NULL,NULL,NULL,NULL),
('06d653b7-a967-4c0e-ae93-e0ca3840fb99','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,9,9,'Step 9','Place the light bar mounts over the studs. Check that the correct bracket is used, by ensuring the vertical side of the bracket faces the centre of the vehicle. Fix the brackets in place using the supplied M8 nyloc nuts and a 13mm socket.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_21.jpeg',NULL,NULL,NULL,NULL),
('102a344a-2033-498d-8c36-520c479c3f76','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,10,10,'Step 10','Install the light bar brackets underneath the TrailBait mounts using supplied fixings. Hand tighten only. Ease light bar into position. Don’t fully tighten bolts, as the angle will need adjustment.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_15.jpeg',NULL,NULL,NULL,NULL),
('86eda433-8faa-4740-ac46-2eb200927223','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,11,11,' ','Install the wiring loom by attaching the terminals to the battery, attaching the piggyback wiring to the high-beam and plugging in all connectors. LED headlights use the grey piggyback plug. Halogen headlights use the black piggyback plug.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_16.png',NULL,NULL,NULL,NULL),
('929affdf-1167-4be0-8382-3c8bcc2d015a','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,12,12,'Step 12','Feed the switch cable through the firewall and attached the supplied switch. Switch will fit the centre console or driver''s panel. Wire in the switch by attached matching coloured wires.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_18.png',NULL,NULL,NULL,NULL),
('73cec037-f2e1-4dfe-9923-376cc5d5f4c4','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,13,13,'Step 13','Temporarily reattach the bumper. Set the beam angle of the light bar (preferably at night, where you can see the best angle visually) and tighten the bolts from step 10.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_22.jpeg',NULL,NULL,NULL,NULL),
('3eb7a69b-557b-405d-b353-a8116ccc621b','5f23e6d6-fa9c-4576-a39f-b935d929fa11',NULL,14,14,'Step 14','Reattach all bolts and clips removed in earlier steps. Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/797bc741-7f31-4b36-aa7f-62389e870bac/step_25.jpeg',NULL,NULL,NULL,NULL),
('4ef3149c-0495-496d-827c-ca1681b37d44','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,14,14,'Attach Piggyback to Headlight','Attach the piggyback to the headlight plug & lead. Halogen models will piggyback directly off the high beam bulb. (headlight shown off vehicle for demonstration purposes only).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_14.jpeg',NULL,NULL,NULL,NULL),
('eef4461c-0491-4802-8cae-266e14b7ab9b','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,15,15,'Connect Wiring and Reattach Battery','Attach ring terminals from the harness to the battery terminals. Ensure all plugs and switches are attached, then reattach the main battery negative terminal.',NULL,NULL,NULL,NULL,NULL),
('3c01e61f-f9d1-46e1-af50-4c63ba4576fc','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,2,2,'Remove Clips','Remove clips by unscrewing the center pin a few turns before prying open the clip. Use light pressure on the screw to avoid stripping the screw.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_02.jpeg',NULL,NULL,NULL,NULL),
('d222f3a0-056a-4993-b08c-82f139040ac4','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,3,3,'Discard Nuts','Remove the black nuts pictured (on both sides of the vehicle). These can be discarded.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_03.jpeg',NULL,NULL,NULL,NULL),
('84c80482-3c29-4c79-9d95-73731b4fc293','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,4,4,'Attach Side Brackets','Attach the side brackets to the light bar. Position the brackets so the light bar sits forward of the mounting points. Tighten, then loosen 1 turn.
Feed the vertical bolts through the bracket before attaching it, as these can''t be inserted later.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_04.jpeg',NULL,NULL,NULL,NULL),
('3e6edc37-a19b-4ac2-938b-7decf0bce2ba','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,5,5,'Position Light Bar','Lower the light bar into the cavity in front of the intercooler. Let it sit on the ledge on the grille so that it can be easily accessed later. A second person holding the light bar in place (reaching through the grille) would be easier for the following steps.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_05.jpeg',NULL,NULL,NULL,NULL),
('9abf46e2-52c0-47ba-8b3d-837857276400','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,1,1,'Remove bonnet latch handle','Remove the bonnet latch handle.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_01.jpeg',NULL,NULL,NULL,NULL),
('f94500a3-c655-4025-a578-de5583c0d7be','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,1,1,'Remove Grille Cavity Cover','Open the bonnet and remove the grille cavity cover. This has a series of pins holding it in place, and which can be released by unwinding the centre with a screwdriver and prying out the clip.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_01.jpeg',NULL,NULL,NULL,NULL),
('eba52b3b-f650-4b94-bf40-5bead01fb47b','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,2,2,'Remove Grille Bolts','Remove the two bolts attaching the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_02.jpeg',NULL,NULL,NULL,NULL),
('966e9e14-36e2-49ce-bd02-b00a0b90d922','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,3,3,'Remove Grille Trim Piece','Remove the trim piece from the bottom of the grille. Carefully pry it off starting with one side, and popping each clip along the length. A plastic trim removal tool is recommended for this step.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_03.jpeg',NULL,NULL,NULL,NULL),
('a016d600-a305-447b-a903-a600fc21c8cd','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,4,4,'Remove Grille Base Bolts','Remove the three bolts along the base of the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_04.jpeg',NULL,NULL,NULL,NULL),
('036ab1a0-6041-4c54-9beb-c3af7fc0b179','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,5,5,'Remove Grille','Pop the clips at each headlight by pulling outwards from the vehicle, and remove the grille. Set the grille aside. Take care with this step as the grille may suddenly come loose.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_05.jpeg',NULL,NULL,NULL,NULL),
('fed2651a-157a-487a-95d3-8edcd0baa061','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,6,6,'Attach Centre U Bracket','Skip this step if you have the 26" kit.
Attach the centre U bracket with the supplied M8 stud plate, washers and nut.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_06.jpeg',NULL,NULL,NULL,NULL),
('242cc902-3568-41b2-992b-befc671e2822','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,7,7,'Remove Bolt and Clip','Starting on the driver''s side, remove the bolt & clip pictured. Set aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_07.jpeg',NULL,NULL,NULL,NULL),
('450ee9d7-a932-4283-9c55-cb9491178e4a','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,8,8,'Reattach Bolt and Clip','Reattach the bolt & clip fixing the L bracket in place, as pictured.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_08.jpeg',NULL,NULL,NULL,NULL),
('f3ae2bdf-cc7e-4b11-9293-2f37b8e2fbab','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,9,9,'Attach Light Bar','Attach the light bar using the supplied end bolts.
Repeat steps 7 & 8 for the passenger side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_09.jpeg',NULL,NULL,NULL,NULL),
('aa7289cb-c135-4e5b-9a20-899ddb0c3d09','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,10,10,'Locate Wiring Harness','Locate the pre-wired light bar harness in the engine bay. They are yellow wires taped to the engine harness forward of the fuse box.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_10.jpeg',NULL,NULL,NULL,NULL),
('1b1bc9b2-fa4a-46e4-9170-24ad8bbf2c00','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,11,11,'Prepare Wires','Remove the tape attaching the wires to the engine harness. Cut off the black heat shrink and strip the wires around 10mm.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_11.jpeg',NULL,NULL,NULL,NULL),
('177b443d-de2d-4374-8b6e-54c256f5e3b4','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,12,12,'Crimp Terminals','Using pliers, crimp the supplied terminals onto each wire. Tug the terminal to ensure that it is properly secured to the wire.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_12.jpeg',NULL,NULL,NULL,NULL),
('62317519-59b8-4272-a974-cfa62dbb225e','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,13,13,'Connect T-plug','Push each terminal into the back of the supplied T-plug. A click will be heard once it is in the right position. Ensure the wire with the black stripe is connected to the vertical section of the T-plug.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_13.jpeg',NULL,NULL,NULL,NULL),
('13836470-1353-43aa-80a4-39478cdf4fce','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,14,14,'Connect Wiring Harness to Battery and Light Bars','Connect the wiring harness to the battery terminals as shown here.
Feed the wiring across the engine bay and point the plugs down into the grille cavity, and plug them into the light bars.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_14.jpeg',NULL,NULL,NULL,NULL),
('ce095db9-4976-4335-a0c3-2d208804c27c','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,15,15,'Test Lights','Test the lights to determine the correct angle. If done in daylight, test the lights against a wall to observe the angle in relation to the headlights.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_15.jpeg',NULL,NULL,NULL,NULL),
('9c6b6a1b-0381-474f-abde-93e959cfea05','0d3df100-2911-425a-9b05-4bd17a827a1e',NULL,16,16,'Reinstall Grille and Final Test','Reinstall the grille. Installation is now complete! To turn the lights on, turn AUX6 switch to the on position. The lights will now come on automatically with the high beams.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/a9c76203-36a8-4592-92a0-d832df39c735/step_16.jpeg',NULL,NULL,NULL,NULL),
('6100ca1a-9bdd-4740-bfb6-aee6810269d2','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,8,8,'Attach Light Bar','Use either the front or back slot depending on which is more suitable for the chosen light bar. The light should be as close as possible to the grille without touching. Attach using the supplied fixings. Don''t fully tighten, to allow for adjustment.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_08.jpeg',NULL,NULL,NULL,NULL),
('f952e110-d8e8-4abb-b68e-52bd3ef31c72','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,9,9,'Centre and Tighten Light Bar','Centre the light bar with the grille. Tighten bolts from previous step.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_09.jpeg',NULL,NULL,NULL,NULL),
('40079701-c478-494c-b8ef-5b22bb392cc9','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,10,10,'Secure Coolant Line','Add a cable-tie to the coolant line to keep it from rubbing on the light bar.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_10.jpeg',NULL,NULL,NULL,NULL),
('0e20a079-46c5-42ac-905c-7330b342e3a4','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,11,11,'Disconnect Battery Terminal','Disconnect the negative terminal from the battery. This is an important step, as any wiring done with the battery connected can result in damage to the headlight module.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_11.jpeg',NULL,NULL,NULL,NULL),
('818aa396-9f89-46a3-9c69-984c0a67a9cf','6c8e1f41-fbbb-4df4-86fd-c1f9e9597058',NULL,12,12,'Prepare and Plug in Light Harness','Prepare the light harness in the engine bay in a location close to the battery. Plug in the light bar.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/be29732f-2177-47bd-8a86-da008da5fe51/step_12.jpeg',NULL,NULL,NULL,NULL),
('c1720479-2286-4fee-90a7-fd2420ebabd7','83f31019-c98e-486c-9c6d-dcd631da3903',NULL,6,6,'Reattach Bolts and Secure Stud Plate (Passenger''s Side)','Reattach 10mm bolt on passenger side.
Re-tighten second 10mm bolt.
Attach 13mm nut & large washer to the passenger side stud plate and tighten. Do not overtighten as plastic may split.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/bcae846c-96f6-419a-8173-eea879eafc4b/step_06.jpeg',NULL,NULL,NULL,NULL),
('c5f45c37-5f07-417e-9d2d-e1148cd0bce0','83f31019-c98e-486c-9c6d-dcd631da3903',NULL,7,7,'Fit Light Bar and Wiring','Fit the light bar to the mounts and complete wiring.
Set the beam angle of the light bar (preferably at night, where you can see the best angle visually) and tighten side bolts.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/bcae846c-96f6-419a-8173-eea879eafc4b/step_07.jpeg',NULL,NULL,NULL,NULL),
('192b7918-9440-41db-8d99-2aad833c94aa','83f31019-c98e-486c-9c6d-dcd631da3903',NULL,8,8,'Refit Grille and Cover','Refit upper grille and cover removed in Step 1.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/bcae846c-96f6-419a-8173-eea879eafc4b/step_08.jpeg',NULL,NULL,NULL,NULL),
('b48afdae-5097-497c-bd39-f804b6c25007','96b2a198-5599-44a5-9e28-aa8bda67b6e2',NULL,1,1,'Remove Radiator Cover Panel','Lift the bonnet and remove the plastic radiator cover panel by removing the pins circled in yellow. These can be released by unscrewing the centre pin, and levering them out with a screwdriver.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/72f93685-b8e2-4aab-a8d1-90184a2b56a7/step_01.jpeg',NULL,NULL,NULL,NULL),
('1469ebcb-8321-4f99-8318-3ba05c5d535a','96b2a198-5599-44a5-9e28-aa8bda67b6e2',NULL,2,2,'Remove Black Nuts','Remove the black nuts pictured (on both sides of the vehicle). These can be discarded.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/72f93685-b8e2-4aab-a8d1-90184a2b56a7/step_02.jpeg',NULL,NULL,NULL,NULL),
('bd7c9a71-4ad9-42ec-9682-11c5ccb8870a','96b2a198-5599-44a5-9e28-aa8bda67b6e2',NULL,3,3,'Position Light Bar','Lower the light bar into the cavity in front of the intercooler. Let it sit on the ledge on the grille so that it can be easily accessed later. It may be easier to have a second person hold the light bar in place (reaching through the grille) for the following steps.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/72f93685-b8e2-4aab-a8d1-90184a2b56a7/step_03.jpeg',NULL,NULL,NULL,NULL),
('72b99dc7-b40d-4184-96f9-350ae53244b6','96b2a198-5599-44a5-9e28-aa8bda67b6e2',NULL,4,4,'Attach Brackets','Attach the TrailBait brackets on each side as pictured.
Secure using the supplied 13mm nyloc nuts and washers.
WARNING: Do not remove / alter the Radar module or Radar bracketry!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/72f93685-b8e2-4aab-a8d1-90184a2b56a7/step_04.jpeg',NULL,NULL,NULL,NULL),
('3a94d976-591e-4206-b12e-b7adcb97e31b','96b2a198-5599-44a5-9e28-aa8bda67b6e2',NULL,5,5,'Connect Light Bar and Wiring','Attach the light bar using its provided fixings and complete wiring.
Set the light angle before tightening. We recommend connecting the wiring and testing the light angle at night.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/72f93685-b8e2-4aab-a8d1-90184a2b56a7/step_05.jpeg',NULL,NULL,NULL,NULL),
('1b91c4f2-adab-45c1-809b-eedc7c5ebe08','96b2a198-5599-44a5-9e28-aa8bda67b6e2',NULL,6,6,'Refit Radiator Cover Panel','Refit plastic radiator cover panel removed in Step 1.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/72f93685-b8e2-4aab-a8d1-90184a2b56a7/step_06.jpeg',NULL,NULL,NULL,NULL),
('ab163032-dd25-46fc-a8f5-5f7a776d7b92','b3af92ab-e897-418f-94fa-c322dd171160',NULL,1,1,'Remove Grille','Remove the grille from the vehicle.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8a2ba9a5-f4ed-4b52-9d4a-8bc844617afa/step_01.jpeg',NULL,NULL,NULL,NULL),
('f6f5a5a2-0b81-4491-9ba3-671a5d9f91ca','b3af92ab-e897-418f-94fa-c322dd171160',NULL,2,2,'Remove Shroud','Remove the shroud.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8a2ba9a5-f4ed-4b52-9d4a-8bc844617afa/step_02.jpeg',NULL,NULL,NULL,NULL),
('8248f4ea-ae7d-4b19-bb3a-8348f010c398','b3af92ab-e897-418f-94fa-c322dd171160',NULL,3,3,'Measure and Drill (Tech Pack Only)','Tech Pack Only: Measure up the required space by mocking up the brackets with the light bar. One pair of brackets on each side of the radar. Once you have both brackets in position mark and drill the holes required for the two smaller bracket pieces.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8a2ba9a5-f4ed-4b52-9d4a-8bc844617afa/step_03.jpeg',NULL,NULL,NULL,NULL),
('e53f80d0-e87c-496f-a72c-3d08ae75bb64','62eebb1e-9646-460a-af02-c7a5d0832eae',NULL,1,1,'Disconnect Battery','Detach the negative terminal from the battery.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/315e05d8-f036-4e58-864a-ca8b3bd0bbbd/step_01.jpeg',NULL,NULL,NULL,NULL),
('c198b31b-1dce-4b42-9c2b-90441f481eb6','62eebb1e-9646-460a-af02-c7a5d0832eae',NULL,2,2,'Route Switch Wire','Route the switch wire from the light bar harness through the engine bay safely, across to the grommet on the driver''s side. Pierce the grommet and feed the wire through into the driver''s footwell.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/315e05d8-f036-4e58-864a-ca8b3bd0bbbd/step_02.jpeg',NULL,NULL,NULL,NULL),
('e0444d24-05d6-417e-bf02-6c714a52e340','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,1,1,'Remove Air Dam and Splash Guards','Under the vehicle, remove the air dam and two splash guards indicated.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_01.jpeg',NULL,NULL,NULL,NULL),
('bdc3576e-7e6b-4baf-9e76-495f84169951','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,2,2,'Remove Bumper Bolts','Remove the bolts underneath the bumper.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_02.jpeg',NULL,NULL,NULL,NULL),
('94481a3b-9423-41dc-ab77-ca8613caee02','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,3,3,'Remove Wheel Arch Liner Clips','Remove the clips from the wheel arch liner in the area of the front bumper.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_03.jpeg',NULL,NULL,NULL,NULL),
('b365964b-3164-44bd-a812-e0641e1f39b7','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,4,4,'Pop Out Flares','Pop out the front section of the flares on either side. They only need to be released up to the bumper split.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_04.jpeg',NULL,NULL,NULL,NULL),
('2f21b2f2-e152-4a54-8305-701a9c59e9d3','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,1,1,'Prepare Engine Bay','Lift the bonnet and remove the plastic radiator cover panel by removing the pins circled in yellow.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_01.jpeg',NULL,NULL,NULL,NULL),
('e925970e-d457-4a0f-bf3b-519ac9607d46','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,5,5,'Remove Grille Cavity Cover','Remove grille cavity cover piece by releasing the pins.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_05.jpeg',NULL,NULL,NULL,NULL),
('7989f460-618d-4f85-8301-32c7c101222e','5fad400c-2c3b-4d8d-bfd3-72afd97d9d39',NULL,1,1,'Mount Bracket','Mount bracket in the pictured location using the existing nuts.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9fa8e1b3-8105-4bc9-bd97-fe3fc5a00ca5/step_04.png',NULL,NULL,NULL,NULL),
('dc19748c-0aae-4b48-ae77-21681f0c7ef4','d9db488b-d98e-4f64-8e4f-aa2523af5cbe',NULL,1,1,'Mount Bracket','Mount the bracket in the pictured location using the supplied fixings.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/ecf30bab-cc82-47dc-923e-4f21c473350f/step_04.jpeg',NULL,NULL,NULL,NULL),
('c1c5d75b-2c8c-4e68-b67c-8444e99b2e5c','49a6001b-eb16-4736-9376-8fd202304eee',NULL,1,1,'Mount Bracket','Mount the bracket in the pictured location using the factory fixings.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/0c0f08ad-eb7f-42d9-8e79-93f17f5cee37/step_04.jpeg',NULL,NULL,NULL,NULL),
('7a341739-c03b-41fe-9b9a-3b602fdfe026','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,6,6,'Attach TrailBait Brackets','Attach the TrailBait brackets on each side as pictured.
WARNING: Do not remove / alter the Radar module or Radar bracketry!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_06.jpeg',NULL,NULL,NULL,NULL),
('d10eb4d6-f55c-44b1-8b80-b8da24d82f28','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,7,7,'Secure with Nuts and Washers','Secure using the supplied 13mm nyloc nuts and washers.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_07.jpeg',NULL,NULL,NULL,NULL),
('db77a18e-a5d7-46a5-8de4-81f6030d3e94','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,8,8,'Final Light Bar Positioning','Raise the light bar up so that the vertical bolts feed through the slots in the TrailBait brackets. Secure with the supplied nuts and washers.
Ensure the light bar is centred with the grille before tightening.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_08.jpeg',NULL,NULL,NULL,NULL),
('489d419e-9674-4b52-b852-f9067244bae2','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,9,9,'Tighten Light Bar','Tighten the light once set at the correct angle.
Have patience with longer light bars as they can be difficult to tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_09.jpeg',NULL,NULL,NULL,NULL),
('69a697b3-18f9-4fc4-a746-31e5d2983426','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,10,10,'Attach Piggyback Wiring Loom','Attach the piggyback wiring loom by unplugging the black plug behind the headlight, and reattaching each end to the loom.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_10.jpeg',NULL,NULL,NULL,NULL),
('0b937135-e136-42c4-89d4-004af5784af5','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,11,11,'Connect Light Plug','Attach the light plug and piggyback connector to the main wiring harness.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_11.jpeg',NULL,NULL,NULL,NULL),
('e3164ca2-4727-482b-94ab-646ff6236670','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,12,12,'Connect Power and Ground','Attach the red wire from the harness to the positive battery terminal. Attach the black wire to the ground point pictured.
Bundle the excess wire and secure with a cable tie.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_12.jpeg',NULL,NULL,NULL,NULL),
('55db2894-ebc6-42cb-8820-da8bbed3e6a5','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,13,13,'Route Switch Wire (Optional)','Detach the switch wire from the main harness at the screw plug.
Make a hole in the passenger side firewall grommet and thread the harness end of the switch wire through and pull into the cabin.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_13.jpeg',NULL,NULL,NULL,NULL),
('60e1b099-1139-4ff9-93e6-83ed75e0c401','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,14,14,'Install Cabin Switch (Optional)','Run the switch wire across the base of the dashboard to the drivers side.
Remove a switch blank and install the supplied switch.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_14.jpeg',NULL,NULL,NULL,NULL),
('f66ba18d-cd30-432f-b50e-582ba59e1b73','b1e2a160-a4d7-45b6-b62e-a59a5036f086',NULL,15,15,'Installation Complete','Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b672544b-3a2e-4317-a079-6ad39ce939c1/step_15.jpeg',NULL,NULL,NULL,NULL),
('204eaf67-06f9-4fbc-94bc-12d6e04f764d','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,2,2,'Remove grille cavity cover','Remove the clips from the grille cavity cover. Remove the cover.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_02.jpeg',NULL,NULL,NULL,NULL),
('46993961-e1e6-40d1-ac40-655aec614028','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,3,3,'Remove top grille bolts','Remove the top bolts from the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_03.jpeg',NULL,NULL,NULL,NULL),
('3243b6b5-3199-41b5-9808-c24a55a47384','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,4,4,'Remove inner guard bolts','Remove bolts from the inner guard on each side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_04.jpeg',NULL,NULL,NULL,NULL),
('fc4b7261-c3e0-40a1-9512-daec44d74842','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,1,1,'Remove Grille Cavity Cover','Open the bonnet and remove the grille cavity cover. This has 13 clips holding it in place.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_01.jpeg',NULL,NULL,NULL,NULL),
('1bd070c4-f5be-4c8d-a238-ed58f3fdb0f2','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,2,2,'Remove Grille Bolts','Remove and retain the two bolts attaching the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_02.jpeg',NULL,NULL,NULL,NULL),
('dda41c16-772b-4a3f-9969-6ab311275616','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,3,3,'Disconnect Loom and Tubing','Disconnect the camera loom & washer tubing.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_03.jpeg',NULL,NULL,NULL,NULL),
('afd4b9f1-0e9e-4789-b187-68cb154a8dbd','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,4,4,'Release Grille Section','Starting on the driver''s side, pull firmly on the grille section by the headlight. This will pop out slightly.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_04.jpeg',NULL,NULL,NULL,NULL),
('e06b25d9-847a-44ee-b071-bcc63550d103','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,5,5,'Release Grille Clips','Gently pull the grille forward, and release the clips which are found behind the area circled. Repeat steps 3 & 4 on the passenger side. These clips hold very tight, so take your time with this step.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_05.jpeg',NULL,NULL,NULL,NULL),
('c9acfd83-d2f6-413c-a7ca-b66d27c09642','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,6,6,'Remove Grille','Work along the grille and carefully pop the clips running along the base of the grille. Take care that the grille does not fall down after it has been released. Set the grille aside.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_06.jpeg',NULL,NULL,NULL,NULL),
('4f2852d1-9f32-4ad9-ae67-f937df237126','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,7,7,'Remove Bolt and Clip','Starting on the driver''s side, remove and retain the bolt and clip pictured.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_07.jpeg',NULL,NULL,NULL,NULL),
('5739d75a-1622-484b-806b-f81c0c2a22a5','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,8,8,'Install L-Bracket','Slide the L bracket into position, so that the two holes align. Ensure the bracket sits beneath the bumper plastic as shown. Reinsert the bolt & clip.
Note: pulling the bumper forward gives more room to insert the bracket.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_08.jpeg',NULL,NULL,NULL,NULL),
('c2cd6f6d-8eb1-499c-92dc-37070b2d639c','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,9,9,'Attach Centre U Bracket','Attach the centre U bracket with the supplied M8 stud, washer and nut.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_09.jpeg',NULL,NULL,NULL,NULL),
('50d5bd27-52ec-4027-ae49-c4c097d10ce7','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,10,10,'Attach Light Bars','Attach the light bars using the supplied end bolts. Don''t fully tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_10.jpeg',NULL,NULL,NULL,NULL),
('4a35f1d6-cb90-4fd9-aea8-8826565f9099','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,5,5,'Loosen guard bolts','Loosen bolts fixing the top of the guard on each side. Do not completely remove the bolts (access via the engine bay).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_05.jpeg',NULL,NULL,NULL,NULL),
('6898d286-eb5d-438e-83a0-4021807ded57','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,6,6,'Detach bumper wings','Detach the wings on each side of the bumper by pulling away from the vehicle.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_06.jpeg',NULL,NULL,NULL,NULL),
('90ab5a32-ccd4-4f28-90fa-fd1515db2718','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,7,7,'Detach bumper and disconnect wiring','Release the clips on each side and detach bumper from the grille. Disconnect power loom and washer line to completely remove the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_07.jpeg',NULL,NULL,NULL,NULL),
('41dbad88-806e-4a06-b466-9e1f9f2d7262','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,8,8,'Remove headlight bracket bolts and air guides','Remove bolts from the headlight bracket on each side. Detach the plastic air guides.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_08.jpeg',NULL,NULL,NULL,NULL),
('5ee0621d-c0b2-4020-ade6-fe0464c5797b','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,9,9,'Attach light bar brackets','Attach the light bar brackets to the headlight mount, reusing the factory fixings.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_09.jpeg',NULL,NULL,NULL,NULL),
('4afd963f-4e7e-4f7f-b91d-5fe441637784','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,6,6,'Unbolt Grille','Unbolt four bolts holding the grille in place. Ease the tabs up slightly to allow the grille to pull forward. Note - grille and bumper are removed as one attached unit.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_06.jpeg',NULL,NULL,NULL,NULL),
('0a75ce6d-6128-40ea-afe1-7f3c56d96588','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,7,7,'Prepare Bumper for Removal','Place protective material under the bumper before pulling it free. Focus on the areas below each headlight to release the clips. Ease the bumper downwards. It will remain partially in place for the install.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_07.jpeg',NULL,NULL,NULL,NULL),
('2e8700ad-25eb-40e2-9594-b662ec862c40','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,8,8,'Remove Crash Bar Bolts','Remove the four purple bolts holding the crash bar in place.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_08.jpeg',NULL,NULL,NULL,NULL),
('ad9bb60b-ae66-4ffe-8f41-9580e72145d8','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,9,9,'Install Brackets','Bolt the LH and RH TrailBait brackets into position. It requires the plastic pieces to be flexed around the brackets. There is a plastic tab beneath the fold in the bracket which will be pressed out of the way when the bolts are tightened. This piece can be cut out if preferred.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_09.jpeg',NULL,NULL,NULL,NULL),
('289c2cf0-3091-4e7a-b82b-8bd43cd79a4e','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,10,10,'Attach Light Bar','Attach the light bar to the brackets and centre on the slots before tightening.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_10.jpeg',NULL,NULL,NULL,NULL),
('50a31371-08ee-4ba1-8e18-4a798805f60b','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,11,11,'Complete Wiring and Reassembly','Complete wiring and set desired light angle before replacing all parts in the reverse order from the previous steps.
(If you have purchased a full kit, wiring instructions are provided separately)','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_11.jpeg',NULL,NULL,NULL,NULL),
('b6cfe8f1-7222-4711-bcab-b0c01d0ac87c','0eba016b-7134-4dde-a59d-ea9c25fb6f71',NULL,12,12,'Installation Complete','Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/885bbf34-7d37-4675-b35f-8ea3a322b34c/step_12.jpeg',NULL,NULL,NULL,NULL),
('f523c649-eb7a-4b83-9fb8-fa7ae5690704','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,10,10,'Attach and center light bar','Attach light bar underneath the bracket as shown. Centre the light bar with the vehicle before tightening mounts. Test light bar angle before completing the remaining steps.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_10.jpeg',NULL,NULL,NULL,NULL),
('6504316f-df48-4f3e-a578-a6715b4e1dd4','b3af92ab-e897-418f-94fa-c322dd171160',NULL,4,4,'Mount Light Bar Brackets','Mount the light bar brackets using the preexisting bolts on the impact beam.
Tech Pack: use the provided bolts to attach to the drilled holes.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8a2ba9a5-f4ed-4b52-9d4a-8bc844617afa/step_04.jpeg',NULL,NULL,NULL,NULL),
('8b87beac-b29d-45a7-93bc-f3b18e6776b6','b3af92ab-e897-418f-94fa-c322dd171160',NULL,5,5,'Mount Light Bar/s','Mount the light bar/s into the brackets, and lightly tighten to help position the brackets on to the impact beam.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8a2ba9a5-f4ed-4b52-9d4a-8bc844617afa/step_05.jpeg',NULL,NULL,NULL,NULL),
('8b098703-c531-43eb-bdf1-7131e2017320','6c2074c9-8b8a-40c6-bd69-1861a8761952',NULL,1,1,'Mount Bracket','Mount the bracket in the pictured location using the factory bolt.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b3baad35-1722-4797-be6e-ed9257c26261/step_02.jpeg',NULL,NULL,NULL,NULL),
('a3a7d15d-ca56-4815-a791-5a9bba83f16d','b3af92ab-e897-418f-94fa-c322dd171160',NULL,6,6,'Final Tightening and Reassembly','Once you are happy with the position of the lights, reach down and tighten all bolts holding the brackets down to the impact beam. Replace the grille and other parts that were removed and tighten lights in an approximate plumb position.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/8a2ba9a5-f4ed-4b52-9d4a-8bc844617afa/step_06.jpeg',NULL,NULL,NULL,NULL),
('843930d2-edad-4a47-afde-d3eaadeb477c','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,11,11,'Route wiring','Feed wiring through access point & cable tie in position to avoid fouling on grille louvres.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_11.jpeg',NULL,NULL,NULL,NULL),
('2d5662b6-4cb3-4a6f-a134-2026b6fd2520','a1a9cce4-9148-4f65-9ff4-425de7da690d',NULL,12,12,'Reassemble vehicle','Reverse previous steps to reattach bumper, grille and cover panel. (If desired, reattaching the air guides will require some minor trimming).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/eee0cedc-4022-4e41-80a2-04d3c850e4b8/step_12.jpeg',NULL,NULL,NULL,NULL),
('d7cb584c-f95f-449a-923b-19ae11b90880','c16321e7-bfa3-4645-b943-9b03aac6d085',NULL,11,11,'Final Adjustment and Reassembly','Once light is wired in, check light angle and adjust until satisfied, before tightening bolts from Step 10. Reinstall the grille & cavity cover as removed in steps 1 - 6.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/9f6ce425-f8b5-48fd-9ec0-8345dfe04e01/step_11.jpeg',NULL,NULL,NULL,NULL),
('0414e725-68c3-40fb-8fb6-27e03fbf8f3b','81e4005e-4c2b-4ef7-8219-367084f04da8',NULL,1,1,'Remove cover clips','Remove clips holding the cover piece in place by pushing the centre down to release the barb.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/748c2ac8-4fd5-46c3-8ee9-c74834987245/step_01.jpeg',NULL,NULL,NULL,NULL),
('2de1f5fc-b6a4-43ce-910f-8015429a3140','81e4005e-4c2b-4ef7-8219-367084f04da8',NULL,2,2,'Place stud plate','Reaching down into the cavity*, place a stud plate behind the two outside front bar supports as pictured.
*note: front bumper needs to be removed for access on pre-2020 models & Workmates.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/a2da0996-dc61-43f9-96b0-a2271f9e1cb8.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/a2da0996-dc61-43f9-96b0-a2271f9e1cb8.png',NULL,NULL,NULL),
('c89b962d-673a-4687-a0e1-165fa3202cf1','81e4005e-4c2b-4ef7-8219-367084f04da8',NULL,3,3,'Mount light bar brackets','Place the light bar mounts down over the studs. Check that the correct bracket is used, by ensuring the vertical side of the bracket faces the centre of the vehicle.
Fix the brackets in place using the supplied M8 nyloc nuts and a 13mm socket.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/e910cec6-57ef-4067-9a02-d734a9e11c88.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/e910cec6-57ef-4067-9a02-d734a9e11c88.png',NULL,NULL,NULL),
('6f928169-b766-4a7b-a9af-7c8ec5ad40f1','81e4005e-4c2b-4ef7-8219-367084f04da8',NULL,4,4,'Install light bar brackets onto mount','Install the light bar brackets onto the top face of the mount using supplied fixings. Hand tighten only.
Note: Temperature sensor on the centre support may need to be cable-tied in a new position if it fouls on the light bar.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/0eb2c123-2456-473b-abbf-9b3d3308a85c.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/0eb2c123-2456-473b-abbf-9b3d3308a85c.png',NULL,NULL,NULL),
('3eb7ed2f-7bd8-411c-ae4d-81e19d44c9f3','81e4005e-4c2b-4ef7-8219-367084f04da8',NULL,5,5,'Install light bar','Install the light bar into the brackets using the supplied fixings & allen key, and hand tighten. Tighten the bolts fitted in Step 4.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/afe41abc-cdbb-4397-8fe3-a5e9b026558e.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/afe41abc-cdbb-4397-8fe3-a5e9b026558e.png',NULL,NULL,NULL),
('f9846518-a295-4fe3-81e8-811c2e3297db','81e4005e-4c2b-4ef7-8219-367084f04da8',NULL,6,6,'Install wiring loom','Install the wiring loom by attaching terminals to the battery, the piggyback wiring to the high-beam, and plugging in all the connectors.
For LED headlights, use the grey piggyback plug. For Halogen headlights use the black piggyback plug.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/3fc170d3-04fc-4458-86a6-2f804f0d0ddd.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/3fc170d3-04fc-4458-86a6-2f804f0d0ddd.png',NULL,NULL,NULL),
('d2f0f10a-09b5-43eb-a090-8f66e529757d','81e4005e-4c2b-4ef7-8219-367084f04da8',NULL,7,7,'Install switch','Feed the switch cable through the firewall and attached the supplied switch. Switch will fit the centre console or driver''s panel.
Wire the switch in position using the supplied connection.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/7ffcd9cd-e0ef-425d-be2e-1b6e9aa9964b.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/7ffcd9cd-e0ef-425d-be2e-1b6e9aa9964b.png',NULL,NULL,NULL),
('ee2df8ca-6ff1-46c2-b81f-d43f54599dc3','81e4005e-4c2b-4ef7-8219-367084f04da8',NULL,8,8,'Test and complete installation','Switch the light on and ensure the light angle is satisfactory (usually easier to complete at night!).
Tighten bolts installed in Step 5.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/56feecf0-b988-4163-af64-194728b30ace.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/56feecf0-b988-4163-af64-194728b30ace.png',NULL,NULL,NULL),
('2fbc4038-4dcb-43ba-9640-ecfa9732caad','2eeebbf6-e35f-4129-9a57-a4a1a84038a3',NULL,1,1,'Mount Bracket','Mount the bracket in the pictured location using factory fixings.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/5a6f2ee8-b503-410c-9005-922d420e617f.png','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/guide-images/steps/5a6f2ee8-b503-410c-9005-922d420e617f.png',NULL,NULL,NULL),
('0e2ad23b-ae40-46f9-8e8d-b22aa8d74bb5','f320c6c9-436b-48a2-af23-7d780db727de',NULL,1,1,'Mount Bracket','Mount the bracket in the pictured location using the supplied fixings.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/d401ddba-b935-4c73-b17c-3ab14bd8d812/step_02.jpeg',NULL,NULL,NULL,NULL),
('db2d98a9-5966-46a7-9e6d-a64332cdbe47','6cfa5985-20f7-4a58-87ae-a2e9dc8f893c',NULL,1,1,'Mounting the Bracket','Mount the accessory fuse panel mount bracket in the pictured location using the factory fixings.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/bb00d5a7-14f9-4fbe-a7d4-8c02038effd9/step_04.jpeg',NULL,NULL,NULL,NULL),
('bac6f981-3d1b-4c36-84c4-8090d421074a','3e94eaf5-b8ce-49e2-96a6-7d74553e300d',NULL,1,1,'Remove Grille Cavity Cover','Remove the clips from the grille cavity cover using a flat blade screw driver.
Remove and set aside the cover piece.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b2f51eca-db64-4bc9-a78f-37487855809e/step_01.jpeg',NULL,NULL,NULL,NULL),
('6cc84ec5-33aa-4428-8a07-2fd8d8eb1616','3e94eaf5-b8ce-49e2-96a6-7d74553e300d',NULL,2,2,'Remove Grille Clips','Remove two more clips securing the grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b2f51eca-db64-4bc9-a78f-37487855809e/step_02.jpeg',NULL,NULL,NULL,NULL),
('7dc162df-f771-451a-b588-0f0933d13663','3e94eaf5-b8ce-49e2-96a6-7d74553e300d',NULL,3,3,'Disconnect Front Camera (if applicable)','If vehicle has a front camera, disconnect the plug as shown.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b2f51eca-db64-4bc9-a78f-37487855809e/step_03.jpeg',NULL,NULL,NULL,NULL),
('39aa60a1-a38d-44bb-92ae-80fe2ee03614','3e94eaf5-b8ce-49e2-96a6-7d74553e300d',NULL,4,4,'Remove Grille','Pull the grille away from the vehicle starting on one side. Pull in a straight line away from the front. Take care as the grille may fall.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b2f51eca-db64-4bc9-a78f-37487855809e/step_04.jpeg',NULL,NULL,NULL,NULL),
('34bc952f-30d5-4b0b-84e4-4889fd2ac45b','3e94eaf5-b8ce-49e2-96a6-7d74553e300d',NULL,5,5,'Insert Stud Plates','Slide two stud plates into the holes in the front bar as shown. Repeat on the other side.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b2f51eca-db64-4bc9-a78f-37487855809e/step_05.jpeg',NULL,NULL,NULL,NULL),
('c681e1de-b9f5-449b-9a43-448959aec254','8ba2b742-a0e7-4e6d-96bf-b8825c1276a5',NULL,1,1,'Remove Grille Components','Take out the clips holding the cover piece in place, and remove the cover piece.
Remove the single screw from the front of the grille (marked by the arrow in the image). Pop out the two clips found behind the upper grille (marked in yellow). Remove the upper grille.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/81174801-e528-41d7-a46e-cc583563be88/step_01.jpeg',NULL,NULL,NULL,NULL),
('3c7e0c5d-0b8d-445d-b4bd-f81712ca502f','8ba2b742-a0e7-4e6d-96bf-b8825c1276a5',NULL,2,2,'Remove Vertical Support Bolts','Remove 2 x bolts from vertical support using a 12mm socket/spanner.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/81174801-e528-41d7-a46e-cc583563be88/step_02.jpeg',NULL,NULL,NULL,NULL),
('3880301d-94ed-4e65-892d-1f6308c908c0','8ba2b742-a0e7-4e6d-96bf-b8825c1276a5',NULL,3,3,'Remove Black Clip','Remove the black clip at the base of the cavity, on each side (circled in red).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/81174801-e528-41d7-a46e-cc583563be88/step_03.jpeg',NULL,NULL,NULL,NULL),
('a8b685a6-a57c-4c7e-b6ee-28d7cb00055c','8ba2b742-a0e7-4e6d-96bf-b8825c1276a5',NULL,4,4,'Fit Light Brackets','Fit light brackets* to each TrailBait mount as shown. Hand tighten bolts.
*Light brackets differ depending on light bar bracket pictured is for 23.3" option.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/81174801-e528-41d7-a46e-cc583563be88/step_04.jpeg',NULL,NULL,NULL,NULL),
('26111b09-c58f-45bb-9d50-09af595f79ee','8ba2b742-a0e7-4e6d-96bf-b8825c1276a5',NULL,5,5,'Install Assemblies','Install the assemblies into position (shown in the image). Line up the holes in the bracket with the holes in the horizontal support. Note: the TrailBait bracket sits between the vertical support and the horizontal support (see image in step 7).','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/81174801-e528-41d7-a46e-cc583563be88/step_05.jpeg',NULL,NULL,NULL,NULL),
('5977f43d-e706-4e4d-b1c0-2242df7ce4be','8ba2b742-a0e7-4e6d-96bf-b8825c1276a5',NULL,6,6,'Secure T-Bolt','Push the T-Bolt through from behind, at each end hole.
Attach supplied 13mm nyloc nut & large washer to the T-Bolt. Partially tighten.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/81174801-e528-41d7-a46e-cc583563be88/step_06.jpeg',NULL,NULL,NULL,NULL),
('465192e1-9bf1-48b4-aff0-7c2b162672dd','8ba2b742-a0e7-4e6d-96bf-b8825c1276a5',NULL,7,7,'Refit Bolts and Tighten Nuts','Refit bolts removed in step 2, ensuring they feed through the holes in the TrailBait bracket.
Fully tighten nuts fitted in Step 6 before tightening the centre bolts.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/81174801-e528-41d7-a46e-cc583563be88/step_07.jpeg',NULL,NULL,NULL,NULL),
('14f06874-9c41-4c62-97cf-2a074232d841','8ba2b742-a0e7-4e6d-96bf-b8825c1276a5',NULL,8,8,'Position and Tighten Light Bar','Ease the light into position. Take care with the bigger light bars, as these are a tight fit.
Tighten bolts fitted in Step 4. using two 17mm spanners.
Installation complete!','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/81174801-e528-41d7-a46e-cc583563be88/step_08.jpeg',NULL,NULL,NULL,NULL),
('1352d572-e26e-4d63-981f-f96fe37e2dc4','3e94eaf5-b8ce-49e2-96a6-7d74553e300d',NULL,6,6,'Attach Bracket','Attach the bracket to the stud plates as shown. Use the provided washers and locking nuts.
Ensure the bracket is sitting level before fully tightening bolts.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b2f51eca-db64-4bc9-a78f-37487855809e/step_06.jpeg',NULL,NULL,NULL,NULL),
('f3abc39c-3e02-4d05-857c-9a5451308fb0','3e94eaf5-b8ce-49e2-96a6-7d74553e300d',NULL,7,7,'Install Lights','Install the light/s onto the corresponding slots in the brackets.
Take care not to damage intercooler fins when inserting larger lights.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/b2f51eca-db64-4bc9-a78f-37487855809e/step_07.jpeg',NULL,NULL,NULL,NULL),
('847b0ef7-fd8c-43c9-a1fa-433f2399be91','3e94eaf5-b8ce-49e2-96a6-7d74553e300d',NULL,8,8,'Complete Wiring and Reassemble','Complete wiring and test light angle before replacing grille and cover from earlier steps.
