('3908a4dd-98b0-47f3-8938-f5a1b8bc6232','7b6613eb-86c3-4cce-ad7b-e0c092f08ec6',NULL,1,1,'Mount Bracket','Mount the bracket in the pictured location using the supplied fixings.','https://dwzvpraankfpaswjkpdc.supabase.co/storage/v1/object/public/pdf-extracts/e732907c-c984-4258-8645-58b8379c3f3b/step_02.jpeg',NULL,NULL,NULL,NULL),
